function R(a,b){return Math.floor(Math.random()*(b-a+1))+a}
function P(a){return a[R(0,a.length-1)]}
function cl(v,l,h){return Math.max(l,Math.min(h,v))}
function uid(){return Math.random().toString(36).slice(2,10)}

function mkP(pos,q){
  const age=pos==="GK"?R(18,36):R(17,34),base=cl(q+R(-12,12),1,99),at={};
  ["pace","shooting","passing","tackling","heading","stamina","creativity","positioning","handling","reflexes"].forEach(a=>{
    let v=base+R(-15,15);
    if(pos==="GK"&&(a==="handling"||a==="reflexes"))v=base+R(-5,15);
    if(pos==="GK"&&(a==="shooting"||a==="creativity"))v=base+R(-25,-5);
    if((pos==="ST"||pos==="AM")&&a==="shooting")v=base+R(-5,15);
    if(["DC","DL","DR","DM"].includes(pos)&&a==="tackling")v=base+R(-5,15);
    if(["MC","ML","MR","AM"].includes(pos)&&a==="passing")v=base+R(-5,12);
    at[a]=cl(v,1,99);
  });
  const ovr=Math.round(Object.values(at).reduce((s,v)=>s+v,0)/10);
  const loc=currentNameLocale||"en";const names=NAMES[loc]||NAMES.en;
return {id:uid(),nm:P(names.first)+" "+P(names.last),age,pos,at,ovr,wage:Math.round(ovr*ovr*2+R(100,2000)),val:Math.round((ovr*ovr*2+R(100,2000))*R(40,120)),mor:R(60,95),fit:R(70,100),frm:R(40,90),g:0,a:0,ap:0,yc:0,rc:0,inj:0,sus:0};
}
function mkSq(q){
  const s=[];
  ["GK","GK","DL","DC","DC","DC","DR","DM","ML","MC","MC","MC","MR","AM","AM","ST","ST","ST"].forEach(p=>s.push(mkP(p,q)));
  while(s.length<25)s.push(mkP(P(POS),q+R(-10,-3)));
  return s;
}

// ── MATCH ENGINE (with training bonus) ────────────────────
function calcStr(t,trainHist){
  const el=t.xi.map(i=>t.sq.find(p=>p.id===i)).filter(Boolean);
  // Morale affects effective performance: unhappy=0.85, content=1.0, superb=1.08
  const morFactor=(p)=>{const m=p.mor||50;return m>=80?1.08:m>=65?1.03:m>=50?1.0:m>=35?0.93:0.85;};
  const avg=el.reduce((s,p)=>s+p.ovr*(p.fit/100)*(p.frm/80)*morFactor(p),0)/Math.max(el.length,1);
  let m=1;
  if(t.tac==="Ultra Att")m=1.25;
  if(t.tac==="Attacking")m=1.12;
  if(t.tac==="Defensive")m=0.88;
  if(t.tac==="Ultra Def")m=0.75;
  // Training bonuses (only for player team) accumulate over weeks
  let trainBonus=0;
  if(trainHist&&trainHist.length>0){
    const recent=trainHist.slice(-6); // last 6 weeks of training
    const fitW=recent.filter(x=>x==="Fitness").length;
    const defW=recent.filter(x=>x==="Defending").length;
    const attW=recent.filter(x=>x==="Attacking").length;
    const setW=recent.filter(x=>x==="Set Pieces").length;
    // Each week of focused training adds a small bonus
    trainBonus+= fitW*0.4 + defW*0.3 + attW*0.3 + setW*0.25;
  }
  return (avg + trainBonus) * m * (t.rep/80);
}

function preGen(h,a,hTrain,aTrain){
  const hs=calcStr(h,hTrain)*1.12,as=calcStr(a,aTrain),tot=hs+as;
  let hR=(hs/tot)*3.0,aR=(as/tot)*3.0;
  let hConv=1,aConv=1; // conversion rate modifiers
  // Ultra modes affect the openness of the game
  if(h.tac==="Ultra Att"){hR*=1.2;aR*=1.15;}
  else if(h.tac==="Ultra Def"){hR*=0.6;aR*=0.75;}
  if(a.tac==="Ultra Att"){aR*=1.2;hR*=1.15;}
  else if(a.tac==="Ultra Def"){aR*=0.6;hR*=0.75;}
  // Passing style
  if(h.pass==="Short"){hR*=0.9;hConv*=1.15;aR*=0.95;}
  else if(h.pass==="Direct"){hR*=1.15;hConv*=0.9;aR*=1.05;}
  if(a.pass==="Short"){aR*=0.9;aConv*=1.15;hR*=0.95;}
  else if(a.pass==="Direct"){aR*=1.15;aConv*=0.9;hR*=1.05;}
  // Pressing
  if(h.press){hR*=1.08;aR*=0.92;}else{hR*=0.95;aR*=1.05;}
  if(a.press){aR*=1.08;hR*=0.92;}else{aR*=0.95;hR*=1.05;}
  // Tackling — affects opponent chance rate
  if(h.tackle==="Hard"){aR*=0.9;} else if(h.tackle==="Easy"){aR*=1.1;}
  if(a.tackle==="Hard"){hR*=0.9;} else if(a.tackle==="Easy"){hR*=1.1;}

  const hE=h.xi.map(i=>h.sq.find(p=>p.id===i)).filter(Boolean);
  const aE=a.xi.map(i=>a.sq.find(p=>p.id===i)).filter(Boolean);
  const hSet=(hTrain||[]).slice(-6).filter(x=>x==="Set Pieces").length;
  const aSet=(aTrain||[]).slice(-6).filter(x=>x==="Set Pieces").length;
  const hDef=(hTrain||[]).slice(-6).filter(x=>x==="Defending").length;
  const aDef=(aTrain||[]).slice(-6).filter(x=>x==="Defending").length;

  // Card rate modifiers from tackling style
  const hCardMod=h.tackle==="Hard"?1.8:h.tackle==="Easy"?0.4:1;
  const aCardMod=a.tackle==="Hard"?1.8:a.tackle==="Easy"?0.4:1;

  // Offside trap — calculate breakaway risk based on avg defender positioning
  const hDefPos=hE.filter(p=>["DC","DL","DR"].includes(p.pos)).reduce((s,p)=>s+(p.at.positioning||40),0)/(hE.filter(p=>["DC","DL","DR"].includes(p.pos)).length||1);
  const aDefPos=aE.filter(p=>["DC","DL","DR"].includes(p.pos)).reduce((s,p)=>s+(p.at.positioning||40),0)/(aE.filter(p=>["DC","DL","DR"].includes(p.pos)).length||1);

  const ev=[];let hG=0,aG=0;
  for(let m=1;m<=90;m++){
    if(m%9===0&&Math.random()<0.4){const t=Math.random()<hs/tot?"h":"a";ev.push({m,ty:"com",tx:P(CMT.poss).replace("{t}",t==="h"?h.nm:a.nm),hl:0});}
    // Home chances
    if(Math.random()<(hR*2.5)/90){const sh=P(hE.filter(p=>p.pos!=="GK"));if(sh){
      const c=((sh.at.shooting+sh.at.positioning)/200+0.15)*hConv;
      const defPenalty=aDef*0.02;
      if(Math.random()<c*0.45-defPenalty){hG++;ev.push({m,ty:"goal",tm:"h",p:sh.nm,tx:P(CMT.goal).replace("{p}",sh.nm).replace("{t}",h.nm),hl:1});if(Math.random()<0.6){const a2=P(hE.filter(p=>p.id!==sh.id&&p.pos!=="GK"));if(a2)ev.push({m,ty:"ast",tm:"h",p:a2.nm,tx:P(CMT.assist).replace("{p}",a2.nm),hl:0});}}
      else if(Math.random()<0.5)ev.push({m,ty:"sav",tm:"h",p:sh.nm,tx:P(CMT.saved).replace("{p}",sh.nm),hl:0});
      else ev.push({m,ty:"wide",tm:"h",p:sh.nm,tx:P(CMT.wide).replace("{p}",sh.nm),hl:0});
    }}
    // Away chances
    if(Math.random()<(aR*2.5)/90){const sh=P(aE.filter(p=>p.pos!=="GK"));if(sh){
      const c=((sh.at.shooting+sh.at.positioning)/200+0.15)*aConv;
      const defPenalty=hDef*0.02;
      if(Math.random()<c*0.45-defPenalty){aG++;ev.push({m,ty:"goal",tm:"a",p:sh.nm,tx:P(CMT.goal).replace("{p}",sh.nm).replace("{t}",a.nm),hl:1});if(Math.random()<0.6){const a2=P(aE.filter(p=>p.id!==sh.id&&p.pos!=="GK"));if(a2)ev.push({m,ty:"ast",tm:"a",p:a2.nm,tx:P(CMT.assist).replace("{p}",a2.nm),hl:0});}}
      else if(Math.random()<0.5)ev.push({m,ty:"sav",tm:"a",p:sh.nm,tx:P(CMT.saved).replace("{p}",sh.nm),hl:0});
      else ev.push({m,ty:"wide",tm:"a",p:sh.nm,tx:P(CMT.wide).replace("{p}",sh.nm),hl:0});
    }}
    // Offside trap events
    if(h.offside&&Math.random()<0.03){aR*=0.988;ev.push({m,ty:"com",tx:`Offside! ${a.nm} caught by the trap.`,hl:0});
      if(Math.random()<Math.max(0.02,(60-aDefPos)/200)){const sh=P(aE.filter(p=>p.pos==="ST"||p.pos==="AM"));if(sh){aG++;ev.push({m,ty:"goal",tm:"a",p:sh.nm,tx:`The offside trap fails! ${sh.nm} is through on goal and scores!`,hl:1});}}}
    if(a.offside&&Math.random()<0.03){hR*=0.988;ev.push({m,ty:"com",tx:`Offside! ${h.nm} caught by the trap.`,hl:0});
      if(Math.random()<Math.max(0.02,(60-hDefPos)/200)){const sh=P(hE.filter(p=>p.pos==="ST"||p.pos==="AM"));if(sh){hG++;ev.push({m,ty:"goal",tm:"h",p:sh.nm,tx:`The offside trap fails! ${sh.nm} is through on goal and scores!`,hl:1});}}}
    // Set piece goals from corners
    if(Math.random()<0.04){const t=Math.random()<hs/tot?"h":"a";ev.push({m,ty:"cor",tm:t,tx:P(CMT.corner).replace("{t}",t==="h"?h.nm:a.nm),hl:0});
      const setBonus=t==="h"?hSet:aSet;
      if(setBonus>0&&Math.random()<setBonus*0.025){const el=t==="h"?hE:aE;const sc=P(el.filter(p=>p.pos!=="GK"&&(p.at.heading>50)));
        if(sc){if(t==="h")hG++;else aG++;ev.push({m,ty:"goal",tm:t,p:sc.nm,tx:`${sc.nm} heads home from the corner!`,hl:1});}
      }
    }
    // Cards — modified by tackling style
    const baseCard=0.025;
    if(Math.random()<baseCard*hCardMod){const p=P(hE.filter(x=>x.pos!=="GK"));if(p){if(Math.random()<(h.tackle==="Hard"?0.1:0.15))ev.push({m,ty:"red",tm:"h",p:p.nm,tx:P(CMT.red).replace("{p}",p.nm),hl:1});else ev.push({m,ty:"yel",tm:"h",p:p.nm,tx:P(CMT.yellow).replace("{p}",p.nm),hl:1});}}
    if(Math.random()<baseCard*aCardMod){const p=P(aE.filter(x=>x.pos!=="GK"));if(p){if(Math.random()<(a.tackle==="Hard"?0.1:0.15))ev.push({m,ty:"red",tm:"a",p:p.nm,tx:P(CMT.red).replace("{p}",p.nm),hl:1});else ev.push({m,ty:"yel",tm:"a",p:p.nm,tx:P(CMT.yellow).replace("{p}",p.nm),hl:1});}}
    // Injuries
    const hInjRate=h.tac==="Ultra Att"?0.012:h.tackle==="Hard"?0.007:0.005;
    const aInjRate=a.tac==="Ultra Att"?0.012:a.tackle==="Hard"?0.007:0.005;
    if(Math.random()<hInjRate){const p=P(hE);if(p)ev.push({m,ty:"inj",tm:"h",p:p.nm,tx:P(CMT.injury).replace("{p}",p.nm),hl:1});}
    if(Math.random()<aInjRate){const p=P(aE);if(p)ev.push({m,ty:"inj",tm:"a",p:p.nm,tx:P(CMT.injury).replace("{p}",p.nm),hl:1});}
    // Tackles — more with pressing/hard tackling
    const tckRate=0.06*(h.press?1.3:1)*(h.tackle==="Hard"?1.3:h.tackle==="Easy"?0.6:1);
    if(Math.random()<tckRate){const t=Math.random()<0.5?"h":"a";const el=t==="h"?hE:aE;const p=P(el.filter(x=>x.pos!=="GK"));if(p)ev.push({m,ty:"tck",tm:t,p:p.nm,tx:P(CMT.tackle).replace("{p}",p.nm),hl:0});}
    if(m===45)ev.push({m:45,ty:"ht",tx:"Half Time",hl:1,brk:1});
    if(Math.random()<0.015){const t=Math.random()<hs/tot?"h":"a";ev.push({m,ty:"com",tx:P(CMT.press).replace("{t}",t==="h"?h.nm:a.nm),hl:0});}
  }
  ev.sort((a,b)=>a.m-b.m);
  return {ev,hG,aG};
}

function simFast(h,a){
  const r=preGen(h,a,null,null);
  const hE=h.xi.map(i=>h.sq.find(p=>p.id===i)).filter(Boolean);
  const aE=a.xi.map(i=>a.sq.find(p=>p.id===i)).filter(Boolean);
  r.ev.forEach(e=>{const el=e.tm==="h"?hE:aE;const p=el&&e.p?el.find(x=>x.nm===e.p):null;if(e.ty==="goal"&&p)p.g++;if(e.ty==="ast"&&p)p.a++;if(e.ty==="yel"&&p)p.yc++;if(e.ty==="red"&&p)p.rc++;if(e.ty==="inj"&&p)p.inj=R(1,8);});
  hE.forEach(p=>{p.ap++;p.fit=cl(p.fit-R(3,10),30,100);p.frm=cl(p.frm+R(-8,8),20,99);});
  aE.forEach(p=>{p.ap++;p.fit=cl(p.fit-R(3,10),30,100);p.frm=cl(p.frm+R(-8,8),20,99);});
  return r;
}

// ── FIXTURES ──────────────────────────────────────────────
function mkFix(n){
  const ids=[];for(let i=1;i<n;i++)ids.push(i);
  const rounds=[];
  for(let r=0;r<n-1;r++){
    const ms=[];
    ms.push({h:0,a:ids[0],done:0,hg:0,ag:0});
    for(let i=1;i<ids.length/2+0.5;i++){const h=ids[i],a=ids[ids.length-i];if(h!==a)ms.push({h,a,done:0,hg:0,ag:0});}
    rounds.push(ms);ids.unshift(ids.pop());
  }
  return [...rounds,...rounds.map(rd=>rd.map(m=>({h:m.a,a:m.h,done:0,hg:0,ag:0})))];
}

// ── WORLD GEN ─────────────────────────────────────────────
// Phase 1: sim the first half, return world + bottom 6 for picking
function generatePreWorld(){
  const n=TEAMS.length;
  const teams=TEAMS.map((nm,i)=>{
    const q=75-i*2+R(-5,5);const sq=mkSq(q);
    if(i>=14)sq.forEach(p=>{p.frm=cl(p.frm-R(5,20),20,60);p.mor=cl(p.mor-R(5,15),30,70);});
    return {id:uid(),nm,c:TEAM_DATA[i].c,q,sq,form:FORMS[0],tac:"Balanced",pass:"Mixed",tackle:"Normal",press:false,offside:false,bud:R(1,15)*1e6,rep:100-i*4+R(-2,2),isP:false,w:0,d:0,l:0,gf:0,ga:0,pts:0,xi:sq.slice(0,11).map(p=>p.id),sub:sq.slice(11,16).map(p=>p.id)};
  });
  const fix=mkFix(n);
  fix.slice(0,19).forEach(round=>{round.forEach(m=>{
    const h=teams[m.h],a=teams[m.a],r=simFast(h,a);
    m.done=1;m.hg=r.hG;m.ag=r.aG;
    h.gf+=r.hG;h.ga+=r.aG;a.gf+=r.aG;a.ga+=r.hG;
    if(r.hG>r.aG){h.w++;h.pts+=3;a.l++;}else if(r.hG<r.aG){a.w++;a.pts+=3;h.l++;}else{h.d++;h.pts++;a.d++;a.pts++;}
  });});
  const sorted=[...teams].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga));
  // Bottom 6 are the pick options
  const bottom6=sorted.slice(-6).map(t=>teams.indexOf(t));
  teams.forEach(t=>t.sq.forEach(p=>{p.g=0;p.a=0;p.ap=0;p.yc=0;p.rc=0;}));
  return {teams,fix,bottom6,sorted};
}

// Phase 2: apply player ownership to chosen team
function applyPlayerChoice(preWorld,chosenIdx){
  const {teams,fix}=preWorld;
  teams.forEach(t=>{t.isP=false;});
  const pT=teams[chosenIdx];
  pT.isP=true;
  pT.sq.forEach(p=>{p.fit=cl(p.fit-R(0,12),45,88);p.frm=cl(p.frm-R(0,8),25,60);if(Math.random()<0.1)p.inj=R(1,4);p.starts=0;});
  pT.bud=R(2,5)*1e6;
  pT.xi=[];pT.sub=[]; // Start with blank team sheet — manager picks the squad
  return {teams,fix,startWk:19};
}

// ── ASSISTANT MANAGER SCOUTING ────────────────────────────
function getScoutMsg(teams,pIdx,fix,wk){
  const round=fix[wk];if(!round)return null;
  const pm=round.find(m=>m.h===pIdx||m.a===pIdx);if(!pm)return null;
  const isHome=pm.h===pIdx;
  const oppIdx=isHome?pm.a:pm.h;
  const opp=teams[oppIdx];
  const sorted=[...teams].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga));
  const oppPos=sorted.indexOf(opp)+1;
  const myPos=sorted.indexOf(teams[pIdx])+1;
  const oppRelZone=oppPos>=18;
  const oppTop6=oppPos<=6;
  const oppMid=!oppRelZone&&!oppTop6;
  const venue=isHome?"at home":"away";

  let su="", bo="";

  if(oppRelZone){
    su=`Six pointer: ${opp.nm} ${venue}`;
    bo=`Boss, this is a huge game. ${opp.nm} are ${oppPos}${oppPos===1?"st":oppPos===2?"nd":oppPos===3?"rd":"th"} — they're in the relegation zone too. This is a six pointer. Three points here could be the difference between staying up and going down. Their squad is similar quality to ours. We need to go for this one.`;
  } else if(oppTop6){
    su=`Tough one: ${opp.nm} ${venue}`;
    bo=`${opp.nm} are ${oppPos}${oppPos===1?"st":oppPos===2?"nd":oppPos===3?"rd":"th"} and in good form. This is a tough fixture. ${isHome?"At home we might be able to frustrate them and nick something.":"Away from home we'll need to be disciplined."} A point here would be a good result. Maybe consider a more defensive approach.`;
  } else {
    su=`Next up: ${opp.nm} ${venue}`;
    bo=`We've got ${opp.nm} ${venue}. They're ${oppPos}${oppPos===1?"st":oppPos===2?"nd":oppPos===3?"rd":"th"}, mid-table with nothing much to play for. ${isHome?"This is one we should be targeting three points from.":"A winnable game if we get our approach right."} The lads should fancy this one.`;
  }

  // Add form note
  const oppRecent=opp.w+opp.d+opp.l>0?`Their record: P${opp.w+opp.d+opp.l} W${opp.w} D${opp.d} L${opp.l}.`:"";
  bo+=` ${oppRecent}`;

  return {fr:"Asst. Manager",su,bo};
}

// ── BOARD MESSAGES ────────────────────────────────────────
function getBoardMsg(teams,pIdx,wk,lastHG,lastAG,isHome,streak){
  const sorted=[...teams].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga));
  const pt=teams[pIdx];const pos=sorted.indexOf(pt)+1;
  const relZone=pos>=18,justAbove=pos>=15&&pos<=17,safe=pos<=14;
  const won=isHome?(lastHG>lastAG):(lastAG>lastHG);
  const drew=lastHG===lastAG;const lost=!won&&!drew;
  const msgs=[];

  if(won&&relZone)msgs.push({fr:"Chairman",su:"A vital result",bo:"That was exactly what we needed. The players showed real fight today. More of this and we can get ourselves out of trouble."});
  else if(won&&justAbove)msgs.push({fr:"Chairman",su:"Good result",bo:"Pleased with that. Keep picking up points and we'll be fine."});
  else if(won&&safe)msgs.push({fr:"Chairman",su:"Well done",bo:"Another good result. The board are pleased with the progress since your appointment."});
  else if(drew&&relZone)msgs.push({fr:"Chairman",su:"A point gained?",bo:"It's a point. But we need wins. You know the situation."});
  else if(drew&&justAbove)msgs.push({fr:"Chairman",su:"Frustrating",bo:"We should be winning games like that. A draw isn't enough at this stage."});
  else if(lost&&relZone&&streak<=-3)msgs.push({fr:"Chairman",su:"Emergency board meeting",bo:"The board have held an emergency meeting. Your position is under serious review. We need an immediate improvement."});
  else if(lost&&relZone&&streak<=-2)msgs.push({fr:"Chairman",su:"Unacceptable",bo:"This run of form is deeply concerning. The board are watching closely."});
  else if(lost&&relZone)msgs.push({fr:"Chairman",su:"Disappointing",bo:"Another defeat we can't afford. Turn this around quickly."});
  else if(lost&&justAbove)msgs.push({fr:"Chairman",su:"Concerning",bo:"We can't afford to slip back into the bottom three."});
  else if(lost)msgs.push({fr:"Chairman",su:"Not good enough",bo:"The board expected better today."});

  if(wk===24)msgs.push({fr:"Chairman",su:"Transfer window closed",bo:"The January window is shut. This is the squad we have. Make it work."});
  if(wk===30&&relZone)msgs.push({fr:"Chairman",su:"10 games left",bo:"Ten games to save ourselves. I shouldn't need to tell you what's at stake."});
  if(wk===30&&justAbove)msgs.push({fr:"Chairman",su:"Keep going",bo:"10 games left, we're just above the drop zone. Don't let up."});
  if(wk===34&&relZone)msgs.push({fr:"Chairman",su:"Running out of time",bo:"The situation is critical. Results must improve immediately."});
  if(wk===34&&safe)msgs.push({fr:"Chairman",su:"Nearly there",bo:"A few more points should do it. Don't let it slip."});
  if(wk===36&&relZone)msgs.push({fr:"Chairman",su:"Last chance",bo:"Two games left in the relegation zone. Everything rides on this."});

  let sacked=false;
  if(streak<=-4&&relZone&&wk>24)sacked=true;
  if(streak<=-5&&wk>22)sacked=true;
  if(sacked)msgs.push({fr:"Chairman",su:"We need to talk",bo:"The board have lost confidence. Your contract has been terminated. We wish you well."});
  return {msgs,sacked};
}

// ── TRANSFER LIST (with gems) ─────────────────────────────
function mkTL(){
  const l=[];
  // 2-3 genuinely good players (OVR 65-78)
  const goodPos=["ST","AM","MC","DC"];
  for(let i=0;i<3;i++){
    const p=mkP(goodPos[i],R(68,80));
    p.ask=Math.round(R(15,35)*100000);
    p.club=P(["Loan - Juventus","Loan - AC Milan","Loan - Real Madrid","Loan - Barcelona","Loan - Bayern Munich"]);
    l.push(p);
  }
  // Rest are average
  for(let i=0;i<20;i++){
    const p=mkP(P(POS),R(35,62));
    p.ask=Math.round(p.val*(0.3+Math.random()*0.3));
    p.club=P(["Free Agent","Free Agent","Free Agent","Loan - Ajax","Loan - Porto","Loan - Lyon","Loan - Lazio","Loan - Dortmund"]);
    l.push(p);
  }
  // Sort by OVR descending
  l.sort((a,b)=>b.ovr-a.ovr);
  return l;
}

// ── CSS ───────────────────────────────────────────────────
// Tactical arrows based on tactic and position
// Darken a hex colour by a factor (0-1)
function darkenHex(hex,f){
  const r=parseInt(hex.slice(1,3),16),g=parseInt(hex.slice(3,5),16),b=parseInt(hex.slice(5,7),16);
  return `#${Math.round(r*f).toString(16).padStart(2,"0")}${Math.round(g*f).toString(16).padStart(2,"0")}${Math.round(b*f).toString(16).padStart(2,"0")}`;
}
function teamGrad(c){return `linear-gradient(180deg, ${c[0]} 0%, ${darkenHex(c[0],0.7)} 100%)`;}

// Morale state from number
function moraleWord(m){
  if(m>=80)return {txt:"Superb",col:"#40ff40"};
  if(m>=65)return {txt:"Happy",col:"#40c040"};
  if(m>=50)return {txt:"Content",col:"#c0c8e0"};
  if(m>=35)return {txt:"Unsettled",col:"#d0a030"};
  return {txt:"Unhappy",col:"#ff4040"};
}

function tacArrow(tac,pos){
  if(tac==="Balanced")return null;
  if(tac==="Ultra Att"){if(pos==="GK"||pos==="DC")return null;return "↑";}
  if(tac==="Attacking"){if(["ST","AM","ML","MR","DL","DR"].includes(pos))return "↑";return null;}
  if(tac==="Defensive"){if(["DL","DR","DM","ML","MR","MC"].includes(pos))return "↓";return null;}
  if(tac==="Ultra Def"){if(pos==="ST"||pos==="GK")return null;return "↓";}
  return null;
}

