// ── LIVE MATCH ────────────────────────────────────────────
function LiveMatch({teams,pIdx,fix,wk,mEv,mH,mA,otherR,onFinish,onTeams}){
  const [paused,setPaused]=useState(false);
  const [spd,setSpd]=useState(2);
  const [min,setMin]=useState(0);
  const [disp,setDisp]=useState([{m:0,ty:"ko",tx:"Kick Off!",hl:1}]);
  const [hG,setHG]=useState(0);
  const [aG,setAG]=useState(0);
  const [ended,setEnded]=useState(false);
  const [htP,setHtP]=useState(false);
  const [subs,setSubs]=useState(0);
  const [subOff,setSubOff]=useState(null);
  const [mTab,setMTab]=useState("match");
  const ref=useRef(null);const iRef=useRef(null);
  const pt=teams[pIdx];const isH=fix[wk]?.find(m=>m.h===pIdx)!=null;

  useEffect(()=>{if(ref.current)ref.current.scrollTop=ref.current.scrollHeight;},[disp]);
  useEffect(()=>{
    if(paused||ended||htP){if(iRef.current)clearInterval(iRef.current);iRef.current=null;return;}
    const ms={1:1200,2:500,3:150,4:20}[spd]||500;
    iRef.current=setInterval(()=>{setMin(prev=>{
      const next=prev+1;
      if(next>90){setEnded(true);setDisp(d=>[...d,{m:90,ty:"ft",tx:"Full Time!",hl:1}]);return 90;}
      const me=mEv.filter(e=>e.m===next);
      if(me.length>0){setDisp(d=>[...d,...me]);me.forEach(e=>{if(e.ty==="goal"&&e.tm==="h")setHG(g=>g+1);if(e.ty==="goal"&&e.tm==="a")setAG(g=>g+1);});if(me.some(e=>e.ty==="ht"))setHtP(true);}
      return next;
    });},ms);
    return ()=>{if(iRef.current)clearInterval(iRef.current);};
  },[paused,ended,spd,mEv,htP]);

  const doSub=(offId,onId)=>{if(subs>=3)return;const nt=teams.map((t,i)=>i===pIdx?{...t,xi:t.xi.map(x=>x===offId?onId:x),sub:t.sub.filter(x=>x!==onId)}:t);const off=pt.sq.find(p=>p.id===offId),on=pt.sq.find(p=>p.id===onId);onTeams(nt);setSubs(s=>s+1);setDisp(d=>[...d,{m:min,ty:"sub",tx:`SUB: ${on?.nm} ON for ${off?.nm}`,hl:1}]);setSubOff(null);setMTab("match");};
  const chgTac=t=>{onTeams(teams.map((x,i)=>i===pIdx?{...x,tac:t}:x));setDisp(d=>[...d,{m:min,ty:"com",tx:`Tactic changed to ${t}`,hl:1}]);};
  const chgForm=f=>{onTeams(teams.map((x,i)=>i===pIdx?{...x,form:f}:x));setDisp(d=>[...d,{m:min,ty:"com",tx:`Formation changed to ${f.n}`,hl:1}]);};

  const xi=pt.xi.map(i=>pt.sq.find(p=>p.id===i)).filter(Boolean);
  const bench=pt.sub.map(i=>pt.sq.find(p=>p.id===i)).filter(Boolean);

  // Calculate live match ratings from events
  const myTm=isH?"h":"a";
  const matchRatings=useMemo(()=>{
    const r={};
    // Base rating 6.0 for everyone
    xi.forEach(p=>{r[p.nm]=6.0;});
    disp.forEach(e=>{
      if(!e.p||e.tm!==myTm)return;
      if(e.ty==="goal")r[e.p]=(r[e.p]||6.0)+1.2;
      if(e.ty==="ast")r[e.p]=(r[e.p]||6.0)+0.6;
      if(e.ty==="sav")r[e.p]=(r[e.p]||6.0)+0.3;
      if(e.ty==="tck")r[e.p]=(r[e.p]||6.0)+0.15;
      if(e.ty==="yel")r[e.p]=(r[e.p]||6.0)-0.5;
      if(e.ty==="red")r[e.p]=(r[e.p]||6.0)-1.5;
      if(e.ty==="wide")r[e.p]=(r[e.p]||6.0)-0.1;
      if(e.ty==="inj")r[e.p]=(r[e.p]||6.0)-0.8;
    });
    // Clamp between 4.0 and 10.0
    Object.keys(r).forEach(k=>{r[k]=Math.max(4.0,Math.min(10.0,r[k]));});
    return r;
  },[disp,xi,myTm]);

  // Estimate current fitness (drains as match progresses)
  const matchFit=(p)=>{
    const base=p.fit;
    const drain=min*0.15; // loses roughly 13-14% over 90 mins
    return Math.max(20,Math.round(base-drain));
  };

  const ratingCol=(r)=>r>=7.5?"#40ff40":r>=6.5?"#ffd700":r>=5.5?"#c0c8e0":"#ff6060";

  const icon=ty=>({goal:"⚽",yel:"🟨",red:"🟥",inj:"🏥",sub:"🔄",sav:"🧤",wide:"↗",cor:"📐",tck:"🦶",ht:"⏸",ft:"🏁",ko:"📣"}[ty]||"•");
  const tClass=ty=>ty==="goal"?"goal":ty==="yel"||ty==="red"?"card":ty==="ht"||ty==="ft"||ty==="ko"?"big":ty==="inj"?"injury":"";

  return (
    <div style={{background:"#0e1220",minHeight:"100vh",fontFamily:"'Tahoma',sans-serif",fontSize:11,display:"flex",flexDirection:"column"}}>
      <style>{css}</style>
      <div style={{background:teamGrad(pt.c||["#cc1020","#ffd700"]),padding:"5px 10px",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:`1px solid ${(pt.c||["#cc1020","#ffd700"])[1]}`}}>
        <span style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:14,fontWeight:900,color:"#fff",textShadow:"1px 1px 2px rgba(0,0,0,0.5)"}}>{pt.nm}</span>
        <span style={{fontSize:11,color:(pt.c||["","#ffd700"])[1],fontWeight:"bold"}}>Match Day {wk+1}</span>
      </div>
      <div className="cm-panel" style={{margin:2,padding:4}}>
        <div className="cm-sunken" style={{padding:6,textAlign:"center",position:"relative",overflow:"hidden"}}>
          <div style={{position:"absolute",inset:0,backgroundImage:`url(${MATCH_BG})`,backgroundSize:"cover",backgroundPosition:"center",opacity:0.4}} />
          <div style={{position:"relative",zIndex:1}}>
          <div style={{display:"flex",justifyContent:"center",alignItems:"center",gap:8,flexWrap:"wrap"}}>
            <span style={{fontWeight:"bold",fontSize:13,color:isH?"#ffd700":"#c0c8e0"}}>{mH.nm}</span>
            <span style={{fontSize:24,fontWeight:900,color:"#ffd700",minWidth:60,textAlign:"center",letterSpacing:4}}>{hG} - {aG}</span>
            <span style={{fontWeight:"bold",fontSize:13,color:!isH?"#ffd700":"#c0c8e0"}}>{mA.nm}</span>
          </div>
          <div style={{marginTop:4,fontSize:14,fontWeight:900,color:ended?"#ff4040":htP?"#d0a030":"#40c040"}}>{ended?"FULL TIME":htP?"HALF TIME":`${min} min`}</div>
          <div style={{height:4,background:"#1a2040",margin:"4px 0"}}><div style={{height:"100%",background:min<=45?"#2a8a3a":"#c08000",width:`${(min/90)*100}%`,transition:"width 0.3s"}} /></div>
          {/* Latest event flash */}
          {(()=>{const last=disp.filter(e=>e.hl).slice(-1)[0];if(!last||last.ty==="ko")return null;
            const isGoal=last.ty==="goal";
            const bg=isGoal?"#1a2e1a":last.ty==="yel"||last.ty==="red"?"#2e2a10":last.ty==="inj"?"#2e1a1a":"#1a2040";
            const col=isGoal?"#ffd700":last.ty==="red"?"#ff4040":last.ty==="inj"?"#ff8080":"#80b0ff";
            const goalCount=disp.filter(e=>e.ty==="goal").length;
            return <div key={isGoal?`goal-${goalCount}`:""} style={{background:bg,border:"1px solid #2a3050",padding:"4px 8px",marginTop:2,display:"flex",gap:6,alignItems:"center",fontSize:11,
              animation:isGoal?"goalFlash 1.5s ease":"none"}}>
              <span style={{color:"#506080",fontVariantNumeric:"tabular-nums",minWidth:22}}>{last.m}'</span>
              <span style={{minWidth:14}}>{icon(last.ty)}</span>
              <span style={{color:col,fontWeight:"bold",flex:1,overflow:"hidden",whiteSpace:"nowrap",textOverflow:"ellipsis"}}>{last.tx}</span>
            </div>;
          })()}
          </div>
        </div>
        <div style={{display:"flex",gap:2,flexWrap:"wrap",marginTop:2,justifyContent:"center"}}>
          {!ended&&!htP&&<button className="cm-btn" onClick={()=>setPaused(p=>!p)} style={{background:paused?"#2a4060":""}}>{paused?"▶ Resume":"⏸ Pause"}</button>}
          {htP&&!ended&&<button className="cm-btn green" onClick={()=>{setHtP(false);setDisp(d=>[...d,{m:46,ty:"ko",tx:"Second half!",hl:1}]);}}>{"▶"} 2nd Half</button>}
          {!ended&&<>{[1,2,3,4].map(s=> <button key={s} className={`cm-btn${spd===s?" act":""}`} onClick={()=>setSpd(s)} style={{minWidth:32}}>{s===1?"▶":s===2?"▶▶":s===3?"▶▶▶":"⏩"}</button>)}</>}
          {ended&&<button className="cm-btn green" onClick={()=>onFinish(hG,aG,disp)} style={{padding:"4px 20px",fontWeight:"bold"}}>Continue →</button>}
        </div>
        {!ended&&<div style={{display:"flex",gap:1,marginTop:3}}>{[["match","Match"],["subs",`Subs(${3-subs})`],["tactics","Tactics"],["info","Info"]].map(([k,l])=> <button key={k} className={`cm-btn${mTab===k?" act":""}`} onClick={()=>setMTab(k)} style={{flex:1,fontSize:10}}>{l}</button>)}</div>}
      </div>
      <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",margin:"0 2px 2px"}}>
        {(mTab==="match"||ended)&&<div className="cm-panel" style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
          <div className="cm-title" style={{padding:"2px 6px"}}>Commentary</div>
          <div ref={ref} className="cm-sunken" style={{flex:1,overflowY:"auto",maxHeight:"calc(100vh - 300px)"}}>
            {disp.map((e,i)=> <div key={i} className={`ticker-line ${tClass(e.ty)}`}><span style={{color:"#506080",minWidth:26,textAlign:"right",fontVariantNumeric:"tabular-nums"}}>{e.m>0?`${e.m}'`:""}</span><span style={{minWidth:16}}>{icon(e.ty)}</span><span>{e.tx}</span></div>)}
            {!ended&&!htP&&min>0&&min<90&&<div className="ticker-line"><span style={{color:"#506080",minWidth:26,textAlign:"right"}}>{min}'</span><span className="blink" style={{color:"#506080"}}>...</span></div>}
          </div>
        </div>}
        {mTab==="subs"&&!ended&&<div className="cm-panel" style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}><div className="cm-title">Substitutions ({3-subs} remaining)</div><div className="cm-sunken" style={{flex:1,overflowY:"auto"}}>
          {subs>=3?<div style={{padding:8,color:"#ff4040",fontWeight:"bold"}}>No substitutions remaining</div>:<>
            <div style={{padding:"4px 4px 2px",color:"#6090e0",fontWeight:"bold",fontSize:10}}>Player OFF:</div>
            <table className="cm-table" style={{marginBottom:8}}><thead><tr><th style={{textAlign:"left"}}>Name</th><th>Pos</th><th>Fit</th><th>Rtg</th></tr></thead>
            <tbody>{xi.map(p=>{const r=(matchRatings[p.nm]||6.0).toFixed(1);const f=matchFit(p);return <tr key={p.id} onClick={()=>setSubOff(subOff===p.id?null:p.id)} className={subOff===p.id?"sel":""} style={{cursor:"pointer"}}>
              <td style={{textAlign:"left"}}>{p.nm}{p.youth?<span style={{fontSize:8,color:"#d0a030",fontWeight:"bold",marginLeft:4}}>U21</span>:""}</td><td>{p.pos}</td>
              <td style={{color:f<50?"#ff4040":"#c0c8e0"}}>{f}</td>
              <td style={{color:ratingCol(parseFloat(r)),fontWeight:"bold"}}>{r}</td>
            </tr>;})}</tbody></table>
            {subOff&&<><div style={{padding:"4px 4px 2px",color:"#40c040",fontWeight:"bold",fontSize:10}}>Player ON:</div>
              <table className="cm-table"><thead><tr><th style={{textAlign:"left"}}>Name</th><th>Pos</th><th>OVR</th><th>Fit</th></tr></thead>
              <tbody>{bench.map(p=> <tr key={p.id} onClick={()=>doSub(subOff,p.id)} style={{cursor:"pointer"}}>
                <td style={{textAlign:"left"}}>{p.nm}{p.youth?<span style={{fontSize:8,color:"#d0a030",fontWeight:"bold",marginLeft:4}}>U21</span>:""}</td><td>{p.pos}</td>
                <td style={{fontWeight:"bold",color:p.ovr>=55?"#ffd700":"#ff6060"}}>{p.ovr}</td>
                <td style={{color:p.fit<60?"#ff4040":"#40c040"}}>{p.fit}</td>
              </tr>)}</tbody></table>
            </>}
          </>}
        </div></div>}
        {mTab==="tactics"&&!ended&&<div className="cm-panel" style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}><div className="cm-title">Tactics</div><div className="cm-sunken" style={{flex:1,overflowY:"auto",padding:6}}>
          <div style={{fontWeight:"bold",color:"#6090e0",marginBottom:4}}>Tactic:</div>
          <div style={{display:"flex",gap:2,flexWrap:"wrap",marginBottom:8}}>{TACS.map(t=> <button key={t} className={`cm-btn${pt.tac===t?" act":""}`} onClick={()=>chgTac(t)}>{t}</button>)}</div>
          <div style={{fontWeight:"bold",color:"#6090e0",marginBottom:4}}>Style:</div>
          <div style={{display:"flex",gap:4,flexWrap:"wrap",marginBottom:4,fontSize:9}}>
            {["Short","Mixed","Direct"].map(v=><button key={v} className={`cm-btn${pt.pass===v?" act":""}`} onClick={()=>onTeams(teams.map((x,i)=>i===pIdx?{...x,pass:v}:x))} style={{fontSize:9,padding:"2px 5px"}}>{v}</button>)}
            {["Easy","Normal","Hard"].map(v=><button key={v} className={`cm-btn${pt.tackle===v?" act":""}`} onClick={()=>onTeams(teams.map((x,i)=>i===pIdx?{...x,tackle:v}:x))} style={{fontSize:9,padding:"2px 5px"}}>{v}</button>)}
          </div>
          <div style={{display:"flex",gap:4,marginBottom:8}}>
            <button className={`cm-btn${pt.press?" act":""}`} onClick={()=>onTeams(teams.map((x,i)=>i===pIdx?{...x,press:!x.press}:x))} style={{fontSize:9,padding:"2px 5px"}}>Press:{pt.press?"ON":"OFF"}</button>
            <button className={`cm-btn${pt.offside?" act":""}`} onClick={()=>onTeams(teams.map((x,i)=>i===pIdx?{...x,offside:!x.offside}:x))} style={{fontSize:9,padding:"2px 5px"}}>Offside:{pt.offside?"ON":"OFF"}</button>
          </div>
          <div style={{fontWeight:"bold",color:"#6090e0",marginBottom:4}}>Formation:</div>
          <div style={{display:"flex",gap:2,flexWrap:"wrap",marginBottom:8}}>{FORMS.map(f=> <button key={f.n} className={`cm-btn${pt.form.n===f.n?" act":""}`} onClick={()=>chgForm(f)}>{f.n}</button>)}</div>
          <div style={{background:"repeating-linear-gradient(90deg, #1a5c2e 0px, #1a5c2e 20px, #1d6432 20px, #1d6432 40px)",borderRadius:4,padding:12,position:"relative",height:220,border:"2px solid #0e4020",marginBottom:8}}>
            <div style={{position:"absolute",inset:10,border:"1px solid rgba(255,255,255,0.3)"}} />
            <div style={{position:"absolute",left:10,right:10,top:"50%",height:1,background:"rgba(255,255,255,0.2)"}} />
            <div style={{position:"absolute",left:"50%",top:"50%",transform:"translate(-50%,-50%)",width:32,height:32,border:"1px solid rgba(255,255,255,0.2)",borderRadius:99}} />
            {/* Pitch markings - penalty areas */}
            <div style={{position:"absolute",left:"20%",right:"20%",bottom:10,height:"18%",border:"1px solid rgba(255,255,255,0.2)",borderBottom:"none"}} />
            <div style={{position:"absolute",left:"35%",right:"35%",bottom:10,height:"8%",border:"1px solid rgba(255,255,255,0.2)",borderBottom:"none"}} />
            <div style={{position:"absolute",left:"50%",bottom:"22%",transform:"translateX(-50%)",width:24,height:10,borderTopLeftRadius:24,borderTopRightRadius:24,borderTop:"1px solid rgba(255,255,255,0.15)",borderLeft:"1px solid rgba(255,255,255,0.15)",borderRight:"1px solid rgba(255,255,255,0.15)"}} />
            <div style={{position:"absolute",left:"20%",right:"20%",top:10,height:"18%",border:"1px solid rgba(255,255,255,0.2)",borderTop:"none"}} />
            <div style={{position:"absolute",left:"35%",right:"35%",top:10,height:"8%",border:"1px solid rgba(255,255,255,0.2)",borderTop:"none"}} />
            <div style={{position:"absolute",left:"50%",top:"22%",transform:"translateX(-50%)",width:24,height:10,borderBottomLeftRadius:24,borderBottomRightRadius:24,borderBottom:"1px solid rgba(255,255,255,0.15)",borderLeft:"1px solid rgba(255,255,255,0.15)",borderRight:"1px solid rgba(255,255,255,0.15)"}} />
            {pt.form.s.map((pos,i)=>{const pid=pt.xi[i];const p=pid&&pt.sq.find(x=>x.id===pid);const[x,y]=pt.form.xy[i];
              const arrow=tacArrow(pt.tac,pos);
              return <div key={i} style={{position:"absolute",left:`${x}%`,top:`${y}%`,transform:"translate(-50%,-50%)",textAlign:"center",zIndex:2}}>
                {arrow==="↑"&&<div style={{fontSize:10,color:"rgba(255,255,255,0.5)",lineHeight:1,marginBottom:-2}}>↑</div>}
                <div style={{width:20,height:20,borderRadius:99,background:p?(pt.c||["#fff","#fff"])[0]:"rgba(255,255,255,0.2)",border:p?`2px solid ${(pt.c||["#fff","#fff"])[1]}`:"1px dashed rgba(255,255,255,0.4)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:7,fontWeight:900,color:p?(pt.c||["#000","#fff"])[1]:"rgba(255,255,255,0.5)",margin:"0 auto"}}>{p?p.ovr:pos}</div>
                <div style={{fontSize:6,color:"#ffd700",marginTop:1,whiteSpace:"nowrap",textShadow:"0 1px 3px #000"}}>{p?<>{p.nm.split(" ").pop()}{p.youth?<span style={{color:"#d0a030",fontWeight:"bold",marginLeft:1,fontSize:5}}>U21</span>:""}</>:pos}</div>
                {arrow==="↓"&&<div style={{fontSize:10,color:"rgba(255,255,255,0.5)",lineHeight:1,marginTop:-1}}>↓</div>}
              </div>;})}
          </div>
          <div style={{fontWeight:"bold",color:"#6090e0",marginBottom:4,fontSize:10}}>Current XI:</div>
          <table className="cm-table"><thead><tr><th style={{textAlign:"left"}}>Name</th><th>Pos</th><th>Fit</th><th>Rtg</th></tr></thead>
          <tbody>{xi.map(p=>{const r=(matchRatings[p.nm]||6.0).toFixed(1);const f=matchFit(p);return <tr key={p.id}>
            <td style={{textAlign:"left"}}>{p.nm}{p.youth?<span style={{fontSize:8,color:"#d0a030",fontWeight:"bold",marginLeft:4}}>U21</span>:""}</td><td>{p.pos}</td>
            <td style={{color:f<50?"#ff4040":"#c0c8e0"}}>{f}</td>
            <td style={{color:ratingCol(parseFloat(r)),fontWeight:"bold"}}>{r}</td>
          </tr>;})}</tbody></table>
        </div></div>}
        {mTab==="info"&&!ended&&<div className="cm-panel" style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}><div className="cm-title">Other Results</div><div className="cm-sunken" style={{flex:1,overflowY:"auto"}}>
          {otherR.map((r,i)=> <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"3px 6px",borderBottom:"1px solid #1e2540",fontSize:10}}><span>{r.home}</span><span style={{fontWeight:"bold"}}>{r.hg}-{r.ag}</span><span>{r.away}</span></div>)}
          {disp.filter(e=>e.ty==="goal").length>0&&<><div style={{padding:"6px 4px 2px",fontWeight:"bold",color:"#6090e0"}}>Goalscorers</div>{disp.filter(e=>e.ty==="goal").map((e,i)=> <div key={i} style={{padding:"2px 6px",fontSize:10}}>{"⚽"} {e.m}' {e.p} ({e.tm==="h"?mH.nm:mA.nm})</div>)}</>}
        </div></div>}
      </div>
    </div>
  );
}

// Strip outer quotes from model text so we don’t double-wrap with \u201c \u201d in News.
function trimPressQuoteOuter(s){
  let t=String(s||"").trim();
  for(let i=0;i<6;i++){
    const u=t.replace(/^[\u201c\u201e"]+/,"").replace(/[\u201d"]+$/,"").trim();
    if(u===t)break;
    t=u;
  }
  return t;
}

// ── MAIN ──────────────────────────────────────────────────
export default function RM(){
  const [scr,setScr]=useState("title");
  const [league,setLeague]=useState(LEAGUE_KEYS[0]);
  const [teams,setTeams]=useState([]);
  const [pIdx,setPIdx]=useState(0);
  const [wk,setWk]=useState(19);
  const [fix,setFix]=useState([]);
  const [tab,setTab]=useState("squad");
  const [fixSub,setFixSub]=useState("fixtures");
  const [sel,setSel]=useState(null);
  const [selT,setSelT]=useState(null);
  const [last,setLast]=useState(null);
  const [tList,setTList]=useState([]);
  const [news,setNews]=useState([]);
  const [sBy,setSBy]=useState("ovr");
  const [sDir,setSDir]=useState(-1);
  const [fPos,setFPos]=useState("ALL");
  const [slotSel,setSlotSel]=useState(null);
  const [teamTalk,setTeamTalk]=useState(null);
  const [talkScreen,setTalkScreen]=useState(false);
  const [showIntel,setShowIntel]=useState(false);
  const [mustWinCount,setMustWinCount]=useState(0);
  const [careerHistory,setCareerHistory]=useState([]);
  const [showCareer,setShowCareer]=useState(false);
  const [endTab,setEndTab]=useState("news");
  const gamesRef=useRef(null);
  const nextGameRef=useRef(null);
  /** After a match, re-run autoSave when the async press quote is appended to news. */
  const pressSaveRef=useRef(null);
  const pressNonceRef=useRef(0);
  const [streak,setStreak]=useState(0);
  const [training,setTraining]=useState("Fitness");
  /** { headline, data, week, token } while Azure quote is loading; token matches News stub row _press. */
  const [pressPending,setPressPending]=useState(null);

  // Load career history from persistent storage on mount
  useEffect(()=>{
    if(!window.storage)return;
    (async()=>{try{const r=await window.storage.get("career-history");if(r&&r.value)setCareerHistory(JSON.parse(r.value));}catch(e){}})();
  },[]);

  useEffect(()=>{
    if(!pressPending)return;
    const {data,headline,week,token}=pressPending;
    let cancelled=false;
    const appendPressNews=(r,errDetail)=>{
      const raw=r?.quote||"It's been a long day — we'll speak again at the next match.";
      const quote=trimPressQuoteOuter(raw);
      const bo=errDetail?`\u201c${quote}\u201d\n\n\u2014 ${errDetail}`:r&&r.ok?`\u201c${quote}\u201d`:`\u201c${quote}\u201d${r&&r.detail?`\n\n\u2014 ${r.detail}`:""}`;
      const row={w:week,fr:"Media",su:`Press Conference post result — ${headline}`,bo,pc:1};
      setNews(prev=>{
        const idx=token!=null?prev.findIndex(n=>n._press===token):-1;
        const next=idx>=0?(()=>{const cp=[...prev];cp[idx]=row;return cp;})():[...prev,row];
        const p=pressSaveRef.current;
        if(p){
          try{
            void autoSave(p.nt,p.fix,p.wk,next,p.pIdx,p.league,p.trainHist,p.training,p.streak,p.teamTalk,p.mustWinCount);
          }catch(_){/* ignore */}
          pressSaveRef.current=null;
        }
        return next;
      });
      setTab("news");
    };
    // No AbortController cleanup: aborting raced the .then in Strict Mode and skipped appending entirely.
    fetchPressConferenceQuote(data)
      .then(r=>{
        if(cancelled)return;
        setPressPending(null);
        appendPressNews(r);
      })
      .catch(e=>{
        if(cancelled)return;
        setPressPending(null);
        appendPressNews(null,String(e?.message||e));
      });
    return()=>{cancelled=true;};
  },[pressPending]);

  async function saveCareer(entry){
    const updated=[...careerHistory,entry];
    setCareerHistory(updated);
    if(!window.storage)return;
    try{await window.storage.set("career-history",JSON.stringify(updated));}catch(e){}
  }

  // Auto-save system
  const [activeSave,setActiveSave]=useState(null);

  useEffect(()=>{
    if(!window.storage)return;
    (async()=>{try{const r=await window.storage.get("auto-save");if(r&&r.value){const s=JSON.parse(r.value);setActiveSave({team:s.teams[s.pIdx].nm,colors:s.teams[s.pIdx].c||["#ccc","#fff"],wk:s.wk,league:s.league,pos:(()=>{const sorted=[...s.teams].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga));return sorted.indexOf(s.teams[s.pIdx])+1;})(),pts:s.teams[s.pIdx].pts});}}catch(e){}})();
  },[]);

  async function autoSave(t,f,w,n,p,l,th,tr,st,tt,mwc){
    if(!window.storage)return;
    try{await window.storage.set("auto-save",JSON.stringify({teams:t,fix:f,wk:w,news:n,pIdx:p,league:l,trainHist:th,training:tr,streak:st,teamTalk:tt,mustWinCount:mwc}));}catch(e){}
  }
  async function clearSave(){
    if(window.storage)try{await window.storage.delete("auto-save");}catch(e){}
    setActiveSave(null);
  }
  function loadSave(){
    if(!window.storage)return;
    (async()=>{try{const r=await window.storage.get("auto-save");if(r&&r.value){const s=JSON.parse(r.value);
      TEAM_DATA=LEAGUES[s.league];TEAMS=TEAM_DATA.map(t=>t.nm);
      currentNameLocale=LEAGUE_LOCALE[s.league]||"en";
      setLeague(s.league);setTeams(s.teams);setFix(s.fix);setWk(s.wk);setNews(s.news||[]);setPIdx(s.pIdx);
      setTrainHist(s.trainHist||[]);setTraining(s.training||"Fitness");setStreak(s.streak||0);
      setTeamTalk(s.teamTalk||null);setMustWinCount(s.mustWinCount||0);
      setTList(mkTL());setTab("squad");setScr("game");setPressPending(null);pressSaveRef.current=null;
    }}catch(e){console.error(e);}})();
  }

  const [trainHist,setTrainHist]=useState([]); // history of training choices
  const [mm,setMM]=useState(false);
  const [mEv,setMEv]=useState([]);
  const [mH,setMH]=useState(null);
  const [mA,setMA]=useState(null);
  const [mOR,setMOR]=useState([]);
  const [preWorld,setPreWorld]=useState(null); // holds pre-simmed world for pick screen

  const pt=teams[pIdx];
  const sorted=useMemo(()=>[...teams].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga)||b.gf-a.gf),[teams]);
  const pPos=pt?sorted.indexOf(pt)+1:20;
  const windowOpen=wk<24;

  function goToPick(leagueKey){
    const lk=leagueKey||league;
    TEAM_DATA=LEAGUES[lk];
    TEAMS=TEAM_DATA.map(t=>t.nm);
    currentNameLocale=LEAGUE_LOCALE[lk]||"en";
    setLeague(lk);
    const pw=generatePreWorld();
    setPreWorld(pw);
    setScr("pick");
  }

  function startGame(idx){
    const world=applyPlayerChoice(preWorld,idx);
    setTeams(world.teams);setPIdx(idx);setFix(world.fix);setWk(world.startWk);
    setTab("squad");setStreak(0);setSel(null);setLast(null);setTraining("Fitness");setTrainHist([]);setMustWinCount(0);setTeamTalk(null);setPressPending(null);pressSaveRef.current=null;
    const pt=world.teams[idx];
    const s=[...world.teams].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga));
    const pos=s.indexOf(pt)+1;
    const scout=getScoutMsg(world.teams,idx,world.fix,19);
    const n=[
      {w:19,tx:`You have been appointed manager of ${pt.nm}. The previous manager was sacked after a terrible first half.`},
      {w:19,tx:`${pt.nm}: ${pos}${pos===1?"st":pos===2?"nd":pos===3?"rd":"th"} with ${pt.pts} points from 19 games.`},
      {w:19,fr:"Chairman",su:"Welcome to the club",bo:`Nobody said this would be easy. We're in a mess. The January window is open — there's £${(pt.bud/1e6).toFixed(1)}M for signings. Don't get us relegated.`},
      {w:19,fr:"Asst. Manager",su:"Squad assessment",bo:`Boss, the lads are struggling. Morale and fitness are low after a terrible first half. We've got injuries too. Have a look at the squad and set up your training. I'd recommend focusing on fitness first.`},
    ];
    if(scout)n.push({w:19,...scout});
    setNews(n);setTList(mkTL());setPreWorld(null);setActiveSave(null);setScr("game");
    // Initial auto-save
    autoSave(world.teams,world.fix,world.startWk,n,idx,league,[],"Fitness",0,null,0);
  }

  function applyTraining(nt,pI,choice){
    // Apply training effects to player team squad
    const pt=nt[pI];
    pt.sq.forEach(p=>{
      if(p.inj>0)return; // injured players don't benefit
      if(choice==="Fitness"){p.fit=cl(p.fit+R(3,7),30,99);p.frm=cl(p.frm+R(0,2),20,99);}
      if(choice==="Defending"){p.at.tackling=cl(p.at.tackling+R(0,2),1,99);p.at.positioning=cl(p.at.positioning+R(0,2),1,99);p.fit=cl(p.fit+R(1,3),30,99);}
      if(choice==="Attacking"){p.at.shooting=cl(p.at.shooting+R(0,2),1,99);p.at.creativity=cl(p.at.creativity+R(0,2),1,99);p.fit=cl(p.fit+R(1,3),30,99);}
      if(choice==="Set Pieces"){p.at.heading=cl(p.at.heading+R(0,2),1,99);p.fit=cl(p.fit+R(1,3),30,99);}
      // Recalc OVR
      p.ovr=Math.round(Object.values(p.at).reduce((s,v)=>s+v,0)/10);
    });
  }

  function promoteYouth(nt,pI){
    const t=nt[pI];
    const positions=["GK","DL","DC","DR","DM","ML","MC","MR","AM","ST"];
    let promoted=false;
    positions.forEach(pos=>{
      const fitPlayers=t.sq.filter(p=>p.pos===pos&&p.inj===0);
      if(fitPlayers.length<2){
        // Need at least 2 per position for cover - promote a youth player
        const needed=2-fitPlayers.length;
        for(let i=0;i<needed;i++){
          const yp=mkP(pos,R(20,35));
          yp.age=R(17,19);
          yp.fit=R(75,95);
          yp.frm=R(40,60);
          yp.mor=R(60,80);
          yp.youth=true;
          t.sq.push(yp);
          promoted=true;
        }
      }
    });
    return promoted;
  }

  function startLive(){
    setPressPending(null);pressSaveRef.current=null;
    if(wk>=38){endSeason();return;}
    const round=fix[wk];const pm=round.find(m=>m.h===pIdx||m.a===pIdx);if(!pm)return;
    const nt=teams.map(t=>({...t,sq:t.sq.map(p=>({...p,at:{...p.at}}))}));

    // Promote youth if needed
    const youthPromoted=promoteYouth(nt,pIdx);
    if(youthPromoted)setNews(n=>[...n,{w:wk,fr:"Asst. Manager",su:"Youth call-up",bo:"We've had to bring in some U21 lads to cover. They're marked U21 on the squad screen. They're not great but they'll do in an emergency."}]);

    // Auto-fill XI and subs if incomplete
    const pT=nt[pIdx];
    const assigned=new Set([...pT.xi,...pT.sub]);
    const xiBefore=pT.xi.length;
    // Fill XI to 11
    if(pT.xi.length<11){
      const needed=pT.form.s.slice(pT.xi.length);
      needed.forEach(pos=>{
        const match=pT.sq.filter(p=>!assigned.has(p.id)&&p.inj===0&&p.pos===pos).sort((a,b)=>b.ovr-a.ovr)[0]
          ||pT.sq.filter(p=>!assigned.has(p.id)&&p.inj===0).sort((a,b)=>b.ovr-a.ovr)[0];
        if(match){pT.xi.push(match.id);assigned.add(match.id);}
      });
    }
    // Fill subs to 5
    while(pT.sub.length<5){
      const avail=pT.sq.filter(p=>!assigned.has(p.id)&&p.inj===0).sort((a,b)=>b.ovr-a.ovr)[0];
      if(!avail)break;
      pT.sub.push(avail.id);assigned.add(avail.id);
    }
    if(xiBefore<11)setNews(n=>[...n,{w:wk,fr:"Asst. Manager",su:"I picked the team",bo:`Boss, you hadn't finished selecting the squad so I've filled in the gaps. ${11-xiBefore} player${11-xiBefore>1?"s":""} added. Might want to check the lineup.`}]);

    // Apply training before match
    applyTraining(nt,pIdx,training);
    const newTrainHist=[...trainHist,training];
    setTrainHist(newTrainHist);

    const home=nt[pm.h],away=nt[pm.a];
    const isPlayerHome=pm.h===pIdx;
    const result=preGen(home,away,isPlayerHome?newTrainHist:null,isPlayerHome?null:newTrainHist);
    const oR=[];
    round.forEach(m=>{
      if(m===pm)return;
      const h=nt[m.h],a=nt[m.a];const r=simFast(h,a);
      m.done=1;m.hg=r.hG;m.ag=r.aG;
      h.gf+=r.hG;h.ga+=r.aG;a.gf+=r.aG;a.ga+=r.hG;
      if(r.hG>r.aG){h.w++;h.pts+=3;a.l++;}else if(r.hG<r.aG){a.w++;a.pts+=3;h.l++;}else{h.d++;h.pts++;a.d++;a.pts++;}
      oR.push({home:h.nm,away:a.nm,hg:r.hG,ag:r.aG});
    });
    setTeams(nt);setMH(home);setMA(away);setMEv(result.ev);setMOR(oR);setMM(true);
  }

  function finishMatch(hg,ag,disp){
    const nt=teams.map(t=>({...t,sq:t.sq.map(p=>({...p,at:{...p.at}}))}));
    const pm=fix[wk].find(m=>m.h===pIdx||m.a===pIdx);
    const home=nt[pm.h],away=nt[pm.a];const isHome=pm.h===pIdx;
    pm.done=1;pm.hg=hg;pm.ag=ag;
    home.gf+=hg;home.ga+=ag;away.gf+=ag;away.ga+=hg;
    if(hg>ag){home.w++;home.pts+=3;away.l++;}else if(hg<ag){away.w++;away.pts+=3;home.l++;}else{home.d++;home.pts++;away.d++;away.pts++;}

    const hE=home.xi.map(i=>home.sq.find(p=>p.id===i)).filter(Boolean);
    const aE=away.xi.map(i=>away.sq.find(p=>p.id===i)).filter(Boolean);
    disp.forEach(e=>{const el=e.tm==="h"?hE:aE;const p=el&&e.p?el.find(x=>x.nm===e.p):null;
      if(e.ty==="goal"&&p)p.g++;if(e.ty==="ast"&&p)p.a++;if(e.ty==="yel"&&p)p.yc++;if(e.ty==="red"&&p)p.rc++;if(e.ty==="inj"&&p)p.inj=R(1,8);});
    hE.forEach(p=>{p.ap++;p.fit=cl(p.fit-R(3,8),30,100);p.frm=cl(p.frm+R(-6,10),20,99);});
    aE.forEach(p=>{p.ap++;p.fit=cl(p.fit-R(3,8),30,100);p.frm=cl(p.frm+R(-6,10),20,99);});
    // Ultra tactic fitness impact on player's team
    const pTeamXI=isHome?hE:aE;
    const pTac=nt[pIdx].tac;
    if(pTac==="Ultra Att")pTeamXI.forEach(p=>{p.fit=cl(p.fit-R(4,9),20,100);});
    else if(pTac==="Attacking")pTeamXI.forEach(p=>{p.fit=cl(p.fit-R(1,3),25,100);});
    else if(pTac==="Ultra Def")pTeamXI.forEach(p=>{p.fit=cl(p.fit+R(1,4),30,100);}); // conserve energy
    else if(pTac==="Defensive")pTeamXI.forEach(p=>{p.fit=cl(p.fit+R(0,2),30,100);});
    // Pressing fitness drain
    if(nt[pIdx].press)pTeamXI.forEach(p=>{p.fit=cl(p.fit-R(2,5),20,100);});
    // Morale — affected by team talk
    const pWon=isHome?(hg>ag):(ag>hg);const pLost=isHome?(hg<ag):(ag<hg);const pDrew=!pWon&&!pLost;
    const talk=teamTalk||"win";
    const mustWinStale=mustWinCount>=3; // overused, reduced effect
    let morW=R(2,6),morL=R(1,4),frmW=R(1,4); // base morale/form changes
    if(talk==="mustwin"){
      if(mustWinStale){morW=R(1,3);morL=R(2,6);} // players stop responding
      else{morW=R(5,10);morL=R(4,8);frmW=R(2,6);} // huge swing
    }
    else if(talk==="noloss"){morW=R(2,5);morL=R(0,2);} // loss barely hurts
    else if(talk==="tryhard"){morW=R(3,6);morL=R(1,3);nt[pIdx].sq.forEach(p=>{p.fit=cl(p.fit-R(1,3),20,100);});} // extra fitness cost
    else if(talk==="noexpect"){morW=R(1,3);morL=R(0,1);} // minimal swing either way

    if(pWon){nt[pIdx].sq.forEach(p=>{p.mor=cl(p.mor+morW,30,99);p.frm=cl(p.frm+frmW,20,99);});}
    if(pLost){nt[pIdx].sq.forEach(p=>{p.mor=cl(p.mor-morL,25,99);});}
    if(pDrew&&talk==="noloss"){nt[pIdx].sq.forEach(p=>{p.mor=cl(p.mor+R(0,2),30,99);});} // draw is fine with "don't lose"

    // Playing time morale — track starts, reward/punish accordingly
    const mySquad=nt[pIdx];
    const xiSet=new Set(mySquad.xi);
    const unhappyWarnings=[];
    mySquad.sq.forEach(p=>{
      if(p.starts==null)p.starts=0;
      if(xiSet.has(p.id)){
        p.starts++;
        p.mor=cl(p.mor+R(1,2),30,99); // playing = happy
      } else if(p.inj>0||p.youth){
        // injured/youth don't care
      } else if(p.ovr>=45){
        // squad player expects games
        p.mor=cl(p.mor-R(1,3),15,99);
        if(p.mor<35&&p.starts<2)unhappyWarnings.push(p.nm);
      } else if(p.ovr>=35){
        // fringe player, slight drop
        p.mor=cl(p.mor-R(0,1),20,99);
      }
    });

    nt.forEach(t=>t.sq.forEach(p=>{p.fit=cl(p.fit+R(2,5),30,100);if(p.inj>0)p.inj--;if(p.sus>0)p.sus--;}));
    // Remove injured players from XI/subs
    const myT=nt[pIdx];
    myT.xi=myT.xi.filter(id=>{const p=myT.sq.find(x=>x.id===id);return p&&p.inj===0;});
    myT.sub=myT.sub.filter(id=>{const p=myT.sq.find(x=>x.id===id);return p&&p.inj===0;});
    // Promote emergency U21 cover right after injuries are processed so they are visible on the squad screen
    const youthPromotedAfterMatch=promoteYouth(nt,pIdx);

    const newStreak=pWon?Math.max(1,streak+1):pLost?Math.min(-1,streak-1):0;
    setStreak(newStreak);

    const nextWk=wk+1;
    const board=getBoardMsg(nt,pIdx,nextWk,hg,ag,isHome,newStreak);

    const newNews=[...news,{w:nextWk,tx:`${home.nm} ${hg} - ${ag} ${away.nm}`}];
    board.msgs.forEach(m=>newNews.push({w:nextWk,...m}));
    if(nextWk<38&&!board.sacked){const scout=getScoutMsg(nt,pIdx,fix,nextWk);if(scout)newNews.push({w:nextWk,...scout});}
    if(youthPromotedAfterMatch){
      newNews.push({w:nextWk,fr:"Asst. Manager",su:"Youth call-up",bo:"We've had to bring in some U21 lads to cover injuries — look for the U21 tag on the squad list."});
    }
    // Assistant manager morale warnings
    if(unhappyWarnings.length>0){
      const names=unhappyWarnings.slice(0,3).join(", ");
      newNews.push({w:nextWk,fr:"Asst. Manager",su:"Unhappy players",bo:`Boss, ${names}${unhappyWarnings.length>3?` and ${unhappyWarnings.length-3} others`:""} haven't been playing and ${unhappyWarnings.length===1?"is":"are"} getting frustrated. Might want to give ${unhappyWarnings.length===1?"him":"them"} some game time or it'll affect performance.`});
    }

    let pcData=null;
    if(!board.sacked&&nextWk<38){
      const myG=isHome?hg:ag,og=isHome?ag:hg;
      let pcResult="drew";
      if(myG>og)pcResult="won";
      else if(myG<og)pcResult="lost";
      const goalsStr=disp.filter(e=>e.ty==="goal").map(e=>`${e.p} ${e.m}'`).join(", ");
      const squad=nt[pIdx].sq;
      const avgM=Math.round(squad.reduce((s,p)=>s+(p.mor||50),0)/Math.max(1,squad.length));
      const morWord=avgM<45?"low":avgM<58?"mixed":"solid";
      const sn=[...nt].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga)||b.gf-a.gf);
      const pn=sn.indexOf(nt[pIdx])+1;
      const ord=n=>n===1?"st":n===2?"nd":n===3?"rd":"th";
      pcData={
        result:pcResult,
        score:`${myG}-${og}`,
        venue:isHome?"at home":"away",
        opponent:(isHome?away:home).nm,
        goals:goalsStr||undefined,
        morale:morWord,
        position:`${pn}${ord(pn)}`,
        extra:"",
      };
    }

    let finalNews=newNews;
    if(pcData){
      const tok=++pressNonceRef.current;
      const hl=`${home.nm} ${hg} - ${ag} ${away.nm}`;
      pressSaveRef.current={nt,fix,wk:nextWk,pIdx,league,trainHist,training,streak:newStreak,teamTalk,mustWinCount};
      setPressPending({headline:hl,data:pcData,week:nextWk,token:tok});
      finalNews=[...newNews,{w:nextWk,fr:"Media",su:`Press Conference post result — ${hl}`,bo:"Speaking to the press…",pc:1,_press:tok}];
    }else{
      setPressPending(null);pressSaveRef.current=null;
    }

    setTeams(nt);setLast({h:home.nm,a:away.nm,hg,ag});setWk(nextWk);setMM(false);setNews(finalNews);
    if(board.sacked){
      setPressPending(null);pressSaveRef.current=null;
      clearSave();
      const myGames=fix.slice(19,nextWk).map(rd=>rd.find(m=>m.h===pIdx||m.a===pIdx)).filter(m=>m&&m.done);
      let sW=0,sD=0,sL=0,sGF=0,sGA=0;
      myGames.forEach(m=>{const isH=m.h===pIdx;const mg=isH?m.hg:m.ag;const tg=isH?m.ag:m.hg;sGF+=mg;sGA+=tg;if(mg>tg)sW++;else if(mg<tg)sL++;else sD++;});
      const sS=[...nt].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga));
      const sPos=sS.indexOf(nt[pIdx])+1;
      saveCareer({league,team:nt[pIdx].nm,teamColors:nt[pIdx].c||["#ccc","#fff"],outcome:"sacked",finalPos:sPos,pts:nt[pIdx].pts,w:sW,d:sD,l:sL,gf:sGF,ga:sGA,playerOfSeason:null,topScorer:null,bestSigning:null,date:new Date().toISOString().slice(0,10)});
      setScr("sacked");return;
    }
    if(nextWk>=38){setPressPending(null);pressSaveRef.current=null;clearSave();endSeason();return;}
    // Auto-save after each match (includes press stub row when pcData)
    autoSave(nt,fix,nextWk,finalNews,pIdx,league,trainHist,training,newStreak,teamTalk,mustWinCount);
    if(board.msgs.length>0||pcData)setTab("news");
  }

  function endSeason(){
    const s=[...teams].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga));
    const pos=s.indexOf(teams[pIdx])+1;const rel=pos>=18;
    const myT=teams[pIdx];
    const endNews=[];

    // Your record under management (from week 19 onwards)
    const myGames=fix.slice(19).map(rd=>rd.find(m=>m.h===pIdx||m.a===pIdx)).filter(m=>m&&m.done);
    let mW=0,mD=0,mL=0,mGF=0,mGA=0;
    myGames.forEach(m=>{const isH=m.h===pIdx;const mg=isH?m.hg:m.ag;const tg=isH?m.ag:m.hg;mGF+=mg;mGA+=tg;if(mg>tg)mW++;else if(mg<tg)mL++;else mD++;});

    // Club Player of the Season — highest avg rating (apps > 3)
    const eligible=myT.sq.filter(p=>p.ap>3);
    const pots=eligible.length>0?eligible.sort((a,b)=>(b.frm/99*6+4)-(a.frm/99*6+4))[0]:null;
    // Club Top Scorer
    const topSc=myT.sq.filter(p=>p.g>0).sort((a,b)=>b.g-a.g)[0]||null;
    // Most Assists
    const topAst=myT.sq.filter(p=>p.a>0).sort((a,b)=>b.a-a.a)[0]||null;
    // Best Signing — jan window signings only
    const signings=myT.sq.filter(p=>p.signedWk!=null&&p.ap>2);
    const bestSig=signings.length>0?signings.sort((a,b)=>(b.frm/99*6+4)-(a.frm/99*6+4))[0]:null;

    // League Top Scorer (all teams)
    let leagueTopSc=null;let leagueTopG=0;
    teams.forEach(t=>t.sq.forEach(p=>{if(p.g>leagueTopG){leagueTopG=p.g;leagueTopSc={nm:p.nm,team:t.nm,g:p.g};}}));

    // Biggest movers since week 19 — who climbed/fell most
    // We stored pre-appointment positions in preWorld but it's gone, so use the bottom6 approach
    // Simple: compare current pos to midway pts rank
    const relegated=s.slice(17).map(t=>t.nm);
    const champions=s[0];

    // Push news items
    endNews.push({w:38,tx:`FINAL WHISTLE — The season is over.`});
    endNews.push({w:38,tx:`🏆 ${champions.nm} are champions with ${champions.pts} points!`});
    endNews.push({w:38,tx:`⬇ Relegated: ${relegated.join(", ")}`});
    endNews.push({w:38,fr:"Chairman",su:rel?"Relegation confirmed":"End of season",
      bo:rel
        ?`We've been relegated. The club finishes ${pos}${pos===1?"st":pos===2?"nd":pos===3?"rd":"th"} with ${myT.pts} points. The darkest day in the club's recent history. Your temporary contract will not be renewed, but the board thanks you for your efforts in impossible circumstances.`
        :`We're safe! The club finishes ${pos}${pos===1?"st":pos===2?"nd":pos===3?"rd":"th"} with ${myT.pts} points. Thank you for steadying the club during your temporary spell in charge — the board will now look for a long-term appointment.`});
    endNews.push({w:38,fr:"Your Record",su:`${mW}W ${mD}D ${mL}L`,
      bo:`In ${myGames.length} games in charge you won ${mW}, drew ${mD} and lost ${mL}. Goals scored: ${mGF}. Goals conceded: ${mGA}. Points gained: ${mW*3+mD}.`});
    if(pots)endNews.push({w:38,fr:"Award",su:"Club Player of the Season",
      bo:`${pots.nm} (${pots.pos}) has been voted Player of the Season with an average rating of ${(pots.frm/99*6+4).toFixed(1)}. Apps: ${pots.ap}, Goals: ${pots.g}, Assists: ${pots.a}.`});
    if(topSc)endNews.push({w:38,fr:"Award",su:"Club Top Scorer",
      bo:`${topSc.nm} finished as top scorer with ${topSc.g} goal${topSc.g>1?"s":""}${topSc.a>0?` and ${topSc.a} assist${topSc.a>1?"s":""}`:""} in ${topSc.ap} appearances.`});
    if(topAst&&(!topSc||topAst.id!==topSc.id))endNews.push({w:38,fr:"Award",su:"Most Assists",
      bo:`${topAst.nm} led the assists chart with ${topAst.a} assist${topAst.a>1?"s":""} in ${topAst.ap} appearances.`});
    if(bestSig)endNews.push({w:38,fr:"Award",su:"Best January Signing",
      bo:`${bestSig.nm} (${bestSig.pos}) has been the standout signing of the January window. Avg rating: ${(bestSig.frm/99*6+4).toFixed(1)}, Apps: ${bestSig.ap}, Goals: ${bestSig.g}.`});
    if(leagueTopSc)endNews.push({w:38,fr:"League",su:"League Top Scorer",
      bo:`${leagueTopSc.nm} (${leagueTopSc.team}) wins the Golden Boot with ${leagueTopSc.g} goals.`});

    setNews(n=>[...n,...endNews]);
    setTab("news");
    // Save career history
    saveCareer({
      league,team:myT.nm,teamColors:myT.c||["#ccc","#fff"],
      outcome:rel?"relegated":"survived",finalPos:pos,pts:myT.pts,
      w:mW,d:mD,l:mL,gf:mGF,ga:mGA,
      playerOfSeason:pots?{nm:pots.nm,pos:pots.pos,avg:+(pots.frm/99*6+4).toFixed(1)}:null,
      topScorer:topSc?{nm:topSc.nm,goals:topSc.g}:null,
      bestSigning:bestSig?{nm:bestSig.nm,avg:+(bestSig.frm/99*6+4).toFixed(1)}:null,
      date:new Date().toISOString().slice(0,10)
    });
    setScr("end");
  }

  const loanCount=pt?pt.sq.filter(p=>p.signedWk!=null).length:0;
  const canBuy=pt&&pt.bud>0&&windowOpen&&loanCount<10;
  const canSell=pt&&pt.sq.filter(p=>!p.youth).length>18;

  function buy(p){if(!canBuy||pt.bud<p.ask)return;const nt=[...teams];nt[pIdx]={...nt[pIdx],sq:[...nt[pIdx].sq,{...p,g:0,a:0,ap:0,yc:0,rc:0,inj:0,sus:0,signedWk:wk}],bud:nt[pIdx].bud-p.ask};setTeams(nt);setTList(l=>l.filter(x=>x.id!==p.id));
    setNews(n=>[...n,{w:wk,fr:"Transfer",su:`${p.nm} signs`,bo:`${p.nm} has completed his move to the club. ${p.club.includes("Loan")?"Loan until end of season.":""}`}]);
  }
  function sell(p){if(!canSell)return;const pr=Math.round(p.val||0);const nt=[...teams];nt[pIdx]={...nt[pIdx],sq:nt[pIdx].sq.filter(x=>x.id!==p.id),bud:nt[pIdx].bud+pr,xi:nt[pIdx].xi.filter(x=>x!==p.id),sub:nt[pIdx].sub.filter(x=>x!==p.id)};setTeams(nt);setNews(n=>[...n,{w:wk,tx:`${p.nm} sold for £${(pr/1e6).toFixed(1)}M`}]);setSel(null);}
  function assignToSlot(playerId){
    if(!slotSel)return;
    const nt=[...teams];const t={...nt[pIdx]};
    // Remove player from wherever they currently are
    t.xi=t.xi.filter(x=>x!==playerId);
    t.sub=t.sub.filter(x=>x!==playerId);
    if(slotSel.type==="xi"){
      // If slot already has someone, they go back to unassigned
      t.xi=[...t.xi];
      t.xi[slotSel.idx]=playerId;
    } else {
      t.sub=[...t.sub];
      t.sub[slotSel.idx]=playerId;
    }
    nt[pIdx]=t;setTeams(nt);setSlotSel(null);
  }
  function clearSlot(){
    if(!slotSel)return;
    const nt=[...teams];const t={...nt[pIdx]};
    if(slotSel.type==="xi"){t.xi=t.xi.map((x,i)=>i===slotSel.idx?null:x).filter(Boolean);}
    else{t.sub=t.sub.map((x,i)=>i===slotSel.idx?null:x).filter(Boolean);}
    nt[pIdx]=t;setTeams(nt);setSlotSel(null);
  }
  function setForm(f){const nt=[...teams];nt[pIdx]={...nt[pIdx],form:f};setTeams(nt);}
  function setTac(t){const nt=[...teams];nt[pIdx]={...nt[pIdx],tac:t};setTeams(nt);}

  // ── SCREENS ─────────────────────────────────────────────
  if(scr==="title") return (
    <div style={{background:"#0e1220",minHeight:"100vh",fontFamily:"'Tahoma',sans-serif",fontSize:11,display:"flex",flexDirection:"column"}}>
      <style>{css}</style>
      <div style={{background:"linear-gradient(180deg, #cc1020 0%, #a00818 100%)",padding:"5px 10px",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:"1px solid #ffd700"}}>
        <span style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:14,fontWeight:900,color:"#fff",textShadow:"1px 1px 2px rgba(0,0,0,0.5)"}}>Relegation Manager</span>
        <span style={{fontSize:9,color:"#ffd700",fontWeight:"bold"}}>Inspired by CM01/02</span>
      </div>
      <div style={{position:"relative",overflow:"hidden",padding:"20px 16px",textAlign:"center",borderBottom:"1px solid #2a3050"}}>
        <div style={{position:"absolute",inset:0,backgroundImage:`url(${TITLE_BG})`,backgroundSize:"cover",backgroundPosition:"center",opacity:0.4}} />
        <div style={{position:"relative",zIndex:1}}>
          <div style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:20,fontWeight:900,color:"#fff",textShadow:"2px 2px 6px rgba(0,0,0,0.8)",letterSpacing:1}}>Pick a club to save</div>
          <div style={{fontSize:11,color:"#c0c8e0",marginTop:8,textShadow:"1px 1px 4px rgba(0,0,0,0.8)"}}>It's January. 19 games to survive.</div>
          <div style={{fontSize:11,color:"#c0c8e0",marginTop:6,textShadow:"1px 1px 4px rgba(0,0,0,0.8)"}}>You have been brought in til the end of the season to save a team from relegation.</div>
        </div>
      </div>
      {/* Resume save */}
      {activeSave&&!showCareer&&<div onClick={loadSave} style={{margin:"4px 2px 0",padding:"10px 12px",background:"#141830",border:"1px solid #2a6a2a",borderRadius:2,cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center"}}
        onMouseEnter={e=>{e.currentTarget.style.background="#1a2540";}}
        onMouseLeave={e=>{e.currentTarget.style.background="#141830";}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <div style={{width:12,height:12,borderRadius:99,background:activeSave.colors[0],border:`2px solid ${activeSave.colors[1]}`}} />
          <div>
            <div style={{fontWeight:"bold",fontSize:12,color:"#40c040"}}>▶ Resume: {activeSave.team}</div>
            <div style={{fontSize:9,color:"#8090b0",marginTop:2}}>{activeSave.league} — Week {activeSave.wk+1}, {activeSave.pos}{activeSave.pos===1?"st":activeSave.pos===2?"nd":activeSave.pos===3?"rd":"th"} ({activeSave.pts} pts)</div>
          </div>
        </div>
        <button className="cm-btn" onClick={e=>{e.stopPropagation();clearSave();}} style={{fontSize:8,padding:"2px 6px",background:"#4a2020",borderColor:"#6a3030",color:"#ff8080"}}>✕</button>
      </div>}
      <div className="cm-panel" style={{margin:2,flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        {showCareer?<>
          <div style={{padding:"6px 8px",fontWeight:"bold",color:"#6090e0",fontSize:11,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span>Career History</span>
            <button className="cm-btn" onClick={()=>setShowCareer(false)} style={{fontSize:9,padding:"2px 6px"}}>← Back</button>
          </div>
          <div className="cm-sunken" style={{margin:"0 4px",flex:1,overflowY:"auto"}}>
            {careerHistory.length===0?<div style={{padding:12,textAlign:"center",color:"#506080"}}>No career history yet. Complete a season to start building your record.</div>
            :careerHistory.slice().reverse().map((c,i)=><div key={i} style={{padding:"8px 10px",borderBottom:"1px solid #1e2540"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <div style={{width:10,height:10,borderRadius:99,background:c.teamColors[0],border:`2px solid ${c.teamColors[1]}`}} />
                  <span style={{fontWeight:"bold",fontSize:12,color:c.outcome==="survived"?"#40c040":c.outcome==="relegated"?"#ff4040":"#ffd700"}}>{c.team}</span>
                </div>
                <span style={{fontSize:9,color:"#506080"}}>{c.date}</span>
              </div>
              <div style={{fontSize:10,color:"#8090b0",marginTop:3}}>
                {c.league} — {c.outcome==="survived"?"✅ Survived":c.outcome==="relegated"?"❌ Relegated":"⚠ Sacked"} at {c.finalPos}{c.finalPos===1?"st":c.finalPos===2?"nd":c.finalPos===3?"rd":"th"} ({c.pts} pts)
              </div>
              <div style={{fontSize:9,color:"#506080",marginTop:2}}>
                {c.w}W {c.d}D {c.l}L — GF {c.gf} GA {c.ga}
                {c.topScorer?` — Top scorer: ${c.topScorer.nm} (${c.topScorer.goals})`:""}
              </div>
            </div>)}
          </div>
        </>:<>
        <div style={{padding:"6px 8px",fontWeight:"bold",color:"#6090e0",fontSize:11}}>Select League:</div>
        <div className="cm-sunken" style={{margin:"0 4px",flex:1,overflowY:"auto"}}>
          {LEAGUE_KEYS.map(lk=> <div key={lk} onClick={()=>goToPick(lk)} style={{padding:"10px 12px",cursor:"pointer",borderBottom:"1px solid #1e2540",display:"flex",justifyContent:"space-between",alignItems:"center"}}
            onMouseEnter={e=>{e.currentTarget.style.background="#1a2540";}}
            onMouseLeave={e=>{e.currentTarget.style.background="";}}>
            <span style={{fontSize:13,color:"#c0c8e0",fontWeight:"bold"}}>{lk}</span>
            <span style={{fontSize:10,color:"#506080"}}>20 teams ▶</span>
          </div>)}
        </div>
        <div style={{borderTop:"1px solid #1e2540",padding:"5px 10px",textAlign:"center"}}>
          {careerHistory.length>0?<div style={{marginBottom:4}}>
            <div style={{fontSize:10,color:"#8090b0"}}>
              {(()=>{const saved=careerHistory.filter(c=>c.outcome==="survived").length;const rel=careerHistory.filter(c=>c.outcome==="relegated").length;const sacked=careerHistory.filter(c=>c.outcome==="sacked").length;
                return `${careerHistory.length} job${careerHistory.length>1?"s":""}: ${saved} saved, ${rel} relegated, ${sacked} sacked`;})()}
            </div>
            <button className="cm-btn" onClick={()=>setShowCareer(true)} style={{marginTop:4,fontSize:9,padding:"3px 10px"}}>📋 Career History</button>
          </div>:null}
          <div style={{fontSize:9,color:"#303848"}}>v1.2 — A relegation survival experience</div>
        </div>
        </>}
      </div>
    </div>
  );

  if(scr==="pick"&&preWorld) {
    const {teams:pw,bottom6,sorted:pwSorted}=preWorld;
    const pickTeams=bottom6.map(idx=>({idx,t:pw[idx],pos:pwSorted.indexOf(pw[idx])+1})).sort((a,b)=>a.pos-b.pos);
    const lastJob=careerHistory.length>0?careerHistory[careerHistory.length-1]:null;
    return (
    <div style={{background:"#0e1220",minHeight:"100vh",fontFamily:"'Tahoma',sans-serif",fontSize:11,display:"flex",flexDirection:"column"}}>
      <style>{css}</style>
      <div style={{background:"linear-gradient(180deg, #cc1020 0%, #a00818 100%)",padding:"5px 10px",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:"1px solid #ffd700"}}>
        <span style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:14,fontWeight:900,color:"#fff",textShadow:"1px 1px 2px rgba(0,0,0,0.5)"}}>Relegation Manager</span>
        <span style={{fontSize:11,color:"#ffd700",fontWeight:"bold"}}>Choose Your Club</span>
      </div>
      <div style={{background:"#141830",borderBottom:"1px solid #2a3050",padding:"6px 10px",textAlign:"center"}}>
        <div style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:13,fontStyle:"italic",color:"#c0c8e0"}}>{league}</div>
        <div style={{fontSize:9,color:"#506080",marginTop:2}}>These clubs need saving. Pick one.</div>
      </div>
        <div className="cm-panel" style={{margin:2,flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        <div className="cm-sunken" style={{margin:4,flex:1,overflowY:"auto"}}>
          <table className="cm-table">
            <thead><tr><th>#</th><th style={{textAlign:"left"}}>Team</th><th>P</th><th>W</th><th>D</th><th>L</th><th>GD</th><th>Pts</th><th></th></tr></thead>
            <tbody>{pickTeams.map(({idx,t,pos})=>{
              const isLastClub=lastJob&&lastJob.league===league&&lastJob.team===t.nm;
              return <tr key={idx} className={pos>=18?"rel":""} style={{opacity:isLastClub?0.35:1}}>
                <td style={{fontWeight:"bold"}}>{pos}</td>
                <td style={{textAlign:"left"}}>{t.nm}</td>
                <td>{t.w+t.d+t.l}</td><td>{t.w}</td><td>{t.d}</td><td>{t.l}</td>
                <td style={{color:t.gf-t.ga>0?"#40c040":t.gf-t.ga<0?"#ff4040":"#506080"}}>{t.gf-t.ga>0?"+":""}{t.gf-t.ga}</td>
                <td style={{fontWeight:900,color:"#ffd700"}}>{t.pts}</td>
                <td>
                  <button
                    className="cm-btn green"
                    onClick={isLastClub?undefined:()=>startGame(idx)}
                    style={{fontSize:9,padding:"2px 8px",opacity:isLastClub?0.6:1,cursor:isLastClub?"default":"pointer"}}
                  >
                    {isLastClub?"Contract ended":"Manage"}
                  </button>
                </td>
              </tr>;
            })}</tbody>
          </table>
        </div>
        <div style={{padding:"6px",display:"flex",justifyContent:"center"}}>
          <button className="cm-btn" onClick={()=>setScr("title")}>← Back</button>
        </div>
      </div>
    </div>
  );}

  if(!pt) return null;

  if(scr==="sacked") return (
    <div style={{background:"#0e1220",minHeight:"100vh",fontFamily:"'Tahoma',sans-serif",fontSize:11,display:"flex",flexDirection:"column"}}>
      <style>{css}</style>
      <div style={{background:teamGrad(pt.c||["#cc1020","#ffd700"]),padding:"5px 10px",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:`1px solid ${(pt.c||["","#ffd700"])[1]}`}}>
        <span style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:14,fontWeight:900,color:"#fff",textShadow:"1px 1px 2px rgba(0,0,0,0.5)"}}>{pt.nm}</span>
        <span style={{fontSize:11,color:(pt.c||["","#ffd700"])[1],fontWeight:"bold"}}>Manager Sacked</span>
      </div>
      <div style={{background:"#141830",borderBottom:"1px solid #2a3050",padding:"8px 10px",textAlign:"center"}}>
        <div style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:15,fontStyle:"italic",color:"#ff4040"}}>You have been sacked</div>
      </div>
      <div className="cm-panel" style={{margin:2,flex:1,display:"flex",flexDirection:"column"}}>
        <div className="cm-sunken" style={{margin:4,padding:"12px"}}>
          <div style={{fontSize:11,color:"#8090b0",marginBottom:6,textAlign:"center"}}>{pt.nm}: {pPos}{pPos===1?"st":pPos===2?"nd":pPos===3?"rd":"th"} with {pt.pts} points when dismissed.</div>
          <div style={{fontSize:10,color:"#506080",textAlign:"center"}}>Games in charge: {wk-19}</div>
        </div>
        <div style={{padding:"8px",display:"flex",justifyContent:"center"}}>
          <button className="cm-btn" onClick={()=>{setScr("title");setTeams([]);setActiveSave(null);}}>Try Again</button>
        </div>
      </div>
    </div>
  );

  if(scr==="end") return (
    <div style={{background:"#0e1220",minHeight:"100vh",fontFamily:"'Tahoma',sans-serif",fontSize:11,display:"flex",flexDirection:"column"}}>
      <style>{css}</style>
      <div style={{background:pPos>=18?"linear-gradient(180deg, #cc1020 0%, #a00818 100%)":teamGrad(pt.c||["#20a030","#fff"]),padding:"5px 10px",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:`1px solid ${pPos>=18?"#ffd700":(pt.c||["","#fff"])[1]}`}}>
        <span style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:14,fontWeight:900,color:"#fff",textShadow:"1px 1px 2px rgba(0,0,0,0.5)"}}>{pt.nm}</span>
        <span style={{fontSize:11,color:pPos>=18?"#ffd700":(pt.c||["","#fff"])[1],fontWeight:"bold"}}>{pPos>=18?"Relegated":"Survived!"}</span>
      </div>
      <div style={{background:"#141830",borderBottom:"1px solid #2a3050",padding:"8px 10px",textAlign:"center"}}>
        <div style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:15,fontStyle:"italic",color:pPos>=18?"#ff6060":"#60ff60"}}>
          {pPos>=18?`${pt.nm} have been relegated.`:`${pt.nm} have survived!`}
        </div>
        <div style={{fontSize:12,fontWeight:"bold",color:"#ffd700",marginTop:4}}>Final: {pPos}{pPos===1?"st":pPos===2?"nd":pPos===3?"rd":"th"} — {pt.pts} points</div>
      </div>
      <div style={{background:"#141830",borderBottom:"1px solid #2a3050",padding:"4px 10px",display:"flex",justifyContent:"flex-end"}}>
        <button
          className="cm-btn green"
          onClick={()=>{setScr("title");setTeams([]);setActiveSave(null);}}
          style={{fontSize:10,fontWeight:"bold",padding:"4px 14px"}}
        >
          Save another club
        </button>
      </div>
      <div style={{display:"flex",gap:1,margin:"2px 2px 0"}}>
        <button className={`cm-btn${endTab==="news"?" act":""}`} onClick={()=>setEndTab("news")} style={{flex:1}}>Season Summary</button>
        <button className={`cm-btn${endTab==="table"?" act":""}`} onClick={()=>setEndTab("table")} style={{flex:1}}>Final Table</button>
      </div>
      <div className="cm-panel" style={{margin:2,flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        {endTab==="news"?<div className="cm-sunken" style={{margin:4,flex:1,overflowY:"auto"}}>
          {[...news].reverse().map((n,i)=> <div key={i} style={{padding:n.fr?"6px":"3px 6px",borderBottom:"1px solid #1e2540",fontSize:10,borderLeft:n.pc?"3px solid #ffd700":"none",paddingLeft:n.pc?7:undefined}}>
            <span style={{color:"#506080",marginRight:6}}>Wk{n.w}</span>
            {n.fr?<><span style={{color:"#6090e0",fontWeight:"bold"}}>{n.fr}: </span><span style={{color:"#ffd700"}}>{n.su}</span><div style={{color:"#8090b0",marginTop:2,paddingLeft:2,whiteSpace:"pre-wrap"}}>{n.bo}</div></>
            :<span>{n.tx}</span>}
          </div>)}
        </div>
        :<div className="cm-sunken" style={{margin:4,flex:1,overflowY:"auto"}}>
          <table className="cm-table"><thead><tr><th>#</th><th style={{textAlign:"left"}}>Team</th><th>P</th><th>W</th><th>D</th><th>L</th><th>GD</th><th>Pts</th></tr></thead>
            <tbody>{sorted.map((t,i)=> <tr key={t.id} className={t.isP?"sel":i>=17?"rel":""}><td style={{fontWeight:"bold"}}>{i+1}</td><td style={{textAlign:"left"}}>{t.nm}</td><td>{t.w+t.d+t.l}</td><td>{t.w}</td><td>{t.d}</td><td>{t.l}</td><td>{t.gf-t.ga>0?"+":""}{t.gf-t.ga}</td><td style={{fontWeight:900}}>{t.pts}</td></tr>)}</tbody></table>
        </div>}
      </div>
    </div>
  );

  if(mm&&mH&&mA) return <LiveMatch teams={teams} pIdx={pIdx} fix={fix} wk={wk} mEv={mEv} mH={mH} mA={mA} otherR={mOR} onFinish={finishMatch} onTeams={setTeams} />;

  // ── PRE-MATCH TEAM TALK ──────────────────────────────────
  if(talkScreen&&pt){
    const round=fix[wk];const pm=round?.find(m=>m.h===pIdx||m.a===pIdx);
    const isHome=pm?.h===pIdx;
    const oppIdx=isHome?pm?.a:pm?.h;
    const opp=teams[oppIdx];
    const oppSorted=[...teams].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga));
    const oppPos=opp?oppSorted.indexOf(opp)+1:10;
    const oppRelZone=oppPos>=18;
    const oppTop6=oppPos<=6;

    // Assistant manager suggestion
    let asstAdvice="";
    let asstSuggestion="";
    if(oppRelZone){
      asstAdvice=`${opp.nm} are in the relegation zone too — this is a six-pointer. They'll be scrapping for their lives.`;
      asstSuggestion="I'd go with 'Must win' boss. We need these points more than they do.";
    } else if(oppTop6){
      asstAdvice=`${opp.nm} are ${oppPos}${oppPos===1?"st":oppPos===2?"nd":oppPos===3?"rd":"th"}. They're a class above us on paper.`;
      asstSuggestion="Take the pressure off the lads. 'No expectations' might be wise here — a point would be a bonus.";
    } else if(isHome){
      asstAdvice=`${opp.nm} are mid-table, nothing to play for. We're at home.`;
      asstSuggestion="Tell them you expect a win. Home crowd behind us, this is winnable.";
    } else {
      asstAdvice=`Away at ${opp.nm}. They're ${oppPos}${oppPos===1?"st":oppPos===2?"nd":oppPos===3?"rd":"th"}, solid but not unbeatable.`;
      asstSuggestion="'Don't lose' keeps us steady. A point away from home isn't the worst.";
    }
    if(mustWinCount>=3){
      asstAdvice+=` Also boss — the lads are getting tired of the pressure speeches. Might want to ease off the 'must win' talk.`;
    }

    const TALKS=[
      {id:"win",label:"I expect a win",desc:"Standard. Moderate morale boost for a win, moderate drop for a loss."},
      {id:"noloss",label:"Don't lose this",desc:"Cautious. Draw doesn't hurt morale. Loss is a small drop. Win gives a decent boost."},
      {id:"mustwin",label:"This is a must-win",desc:"Maximum pressure. Huge boost if you win. Morale crashes if you lose."+(mustWinCount>=3?" ⚠ Players may not respond.":"")},
      {id:"tryhard",label:"Give it everything",desc:"Motivational. Slight fitness drain but players fight harder. Good morale effect either way."},
      {id:"noexpect",label:"No expectations",desc:"Pressure off. Loss barely hurts morale. Win gives a small lift. Best for tough fixtures."},
    ];

    return (
    <div style={{background:"#0e1220",minHeight:"100vh",fontFamily:"'Tahoma',sans-serif",fontSize:11,display:"flex",flexDirection:"column"}}>
      <style>{css}</style>
      <div style={{background:teamGrad(pt.c||["#cc1020","#ffd700"]),padding:"5px 10px",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:`1px solid ${(pt.c||["","#ffd700"])[1]}`}}>
        <span style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:14,fontWeight:900,color:"#fff",textShadow:"1px 1px 2px rgba(0,0,0,0.5)"}}>{pt.nm}</span>
        <span style={{fontSize:11,color:(pt.c||["","#ffd700"])[1],fontWeight:"bold"}}>Pre-Match</span>
      </div>
      {/* Match info */}
      <div style={{position:"relative",overflow:"hidden",padding:"12px 10px",textAlign:"center",borderBottom:"1px solid #2a3050"}}>
        <div style={{position:"absolute",inset:0,backgroundImage:`url(${MATCH_BG})`,backgroundSize:"cover",backgroundPosition:"center",opacity:0.4}} />
        <div style={{position:"relative",zIndex:1}}>
          <div style={{fontSize:10,color:"#8090b0",marginBottom:4}}>Week {wk+1} — {isHome?"HOME":"AWAY"}</div>
          <div style={{display:"flex",justifyContent:"center",alignItems:"center",gap:10}}>
            <span style={{fontWeight:"bold",fontSize:14,color:"#ffd700"}}>{pt.nm}</span>
            <span style={{fontSize:12,color:"#506080"}}>vs</span>
            <span style={{fontWeight:"bold",fontSize:14,color:"#c0c8e0"}}>{opp?.nm}</span>
          </div>
          <div style={{fontSize:10,color:"#506080",marginTop:4}}>{opp?.nm}: {oppPos}{oppPos===1?"st":oppPos===2?"nd":oppPos===3?"rd":"th"} — {opp?.pts} pts</div>
        </div>
      </div>
      {/* Action buttons - near top like in-game */}
      <div style={{padding:"4px 6px",display:"flex",justifyContent:"space-between",gap:4,background:"#141830",borderBottom:"1px solid #2a3050"}}>
        <button className="cm-btn" onClick={()=>{setTalkScreen(false);setShowIntel(false);}}>← Back</button>
        <div style={{display:"flex",gap:4}}>
          <button className={`cm-btn${showIntel?" act":""}`} onClick={()=>setShowIntel(!showIntel)} style={{padding:"4px 10px"}}>🔍 Intel</button>
          <button className="cm-btn green" onClick={()=>{if(!teamTalk)setTeamTalk("win");if(teamTalk==="mustwin")setMustWinCount(c=>c+1);else setMustWinCount(0);setTalkScreen(false);setShowIntel(false);startLive();}} style={{fontWeight:"bold",padding:"4px 16px"}}>Kick Off ▶</button>
        </div>
      </div>
      {showIntel&&opp?<div className="cm-panel" style={{margin:2,flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        <div style={{padding:"6px 8px",fontWeight:"bold",color:"#6090e0",fontSize:11}}>Opposition Intel: {opp.nm}</div>
        <div className="cm-sunken" style={{margin:"0 4px",flex:1,overflowY:"auto"}}>
          {/* Record & form */}
          <div style={{padding:"6px 8px",borderBottom:"1px solid #1e2540"}}>
            <div style={{display:"flex",gap:10,flexWrap:"wrap",fontSize:10,marginBottom:4}}>
              <span style={{color:"#ffd700",fontWeight:"bold"}}>{oppPos}{oppPos===1?"st":oppPos===2?"nd":oppPos===3?"rd":"th"}</span>
              <span style={{color:"#8090b0"}}>P{opp.w+opp.d+opp.l} W{opp.w} D{opp.d} L{opp.l}</span>
              <span style={{color:"#40c040",fontWeight:"bold"}}>{opp.pts} pts</span>
              <span style={{color:"#8090b0"}}>GF {opp.gf} GA {opp.ga}</span>
            </div>
            {(()=>{const oppGames=[];for(let w=Math.max(0,wk-6);w<wk;w++){const rd=fix[w];const gm=rd.find(m=>m.h===oppIdx||m.a===oppIdx);if(gm&&gm.done){const isOH=gm.h===oppIdx;const won=isOH?gm.hg>gm.ag:gm.ag>gm.hg;const drew=gm.hg===gm.ag;oppGames.push(won?"W":drew?"D":"L");}}
              return <div style={{display:"flex",gap:3,alignItems:"center"}}>
                <span style={{fontSize:9,color:"#506080"}}>Form:</span>
                {oppGames.map((r,i)=><span key={i} style={{width:16,height:16,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:900,borderRadius:2,background:r==="W"?"#2a6a2a":r==="D"?"#5a5a20":"#6a2a2a",color:r==="W"?"#40ff40":r==="D"?"#ffd700":"#ff6060"}}>{r}</span>)}
              </div>;
            })()}
          </div>
          {/* Tactical setup */}
          <div style={{padding:"6px 8px",borderBottom:"1px solid #1e2540"}}>
            <div style={{fontSize:10,color:"#6090e0",fontWeight:"bold",marginBottom:3}}>Tactical Setup</div>
            <div style={{display:"flex",gap:8,flexWrap:"wrap",fontSize:10,color:"#c0c8e0"}}>
              <span>Formation: <b>{opp.form?.n||"4-4-2"}</b></span>
              <span>Mentality: <b>{opp.tac}</b></span>
              <span>Passing: <b>{opp.pass||"Mixed"}</b></span>
              <span>Tackling: <b>{opp.tackle||"Normal"}</b></span>
              {opp.press&&<span style={{color:"#ffd700"}}>Pressing ON</span>}
              {opp.offside&&<span style={{color:"#ffd700"}}>Offside Trap ON</span>}
            </div>
          </div>
          {/* Formation pitch */}
          <div style={{padding:"6px 8px",borderBottom:"1px solid #1e2540"}}>
            <div style={{fontSize:10,color:"#6090e0",fontWeight:"bold",marginBottom:3}}>Starting XI</div>
            <div style={{background:"repeating-linear-gradient(90deg, #1a5c2e 0px, #1a5c2e 20px, #1d6432 20px, #1d6432 40px)",borderRadius:4,position:"relative",height:160,border:"2px solid #0e4020"}}>
              <div style={{position:"absolute",inset:6,border:"1px solid rgba(255,255,255,0.2)"}} />
              <div style={{position:"absolute",left:6,right:6,top:"50%",height:1,background:"rgba(255,255,255,0.15)"}} />
              <div style={{position:"absolute",left:"50%",top:"50%",transform:"translate(-50%,-50%)",width:24,height:24,border:"1px solid rgba(255,255,255,0.15)",borderRadius:99}} />
              {/* Penalty areas */}
              <div style={{position:"absolute",left:"20%",right:"20%",bottom:6,height:"18%",border:"1px solid rgba(255,255,255,0.2)",borderBottom:"none"}} />
              <div style={{position:"absolute",left:"35%",right:"35%",bottom:6,height:"8%",border:"1px solid rgba(255,255,255,0.2)",borderBottom:"none"}} />
              <div style={{position:"absolute",left:"50%",bottom:"21%",transform:"translateX(-50%)",width:22,height:8,borderTopLeftRadius:22,borderTopRightRadius:22,borderTop:"1px solid rgba(255,255,255,0.15)",borderLeft:"1px solid rgba(255,255,255,0.15)",borderRight:"1px solid rgba(255,255,255,0.15)"}} />
              <div style={{position:"absolute",left:"20%",right:"20%",top:6,height:"18%",border:"1px solid rgba(255,255,255,0.2)",borderTop:"none"}} />
              <div style={{position:"absolute",left:"35%",right:"35%",top:6,height:"8%",border:"1px solid rgba(255,255,255,0.2)",borderTop:"none"}} />
              <div style={{position:"absolute",left:"50%",top:"21%",transform:"translateX(-50%)",width:22,height:8,borderBottomLeftRadius:22,borderBottomRightRadius:22,borderBottom:"1px solid rgba(255,255,255,0.15)",borderLeft:"1px solid rgba(255,255,255,0.15)",borderRight:"1px solid rgba(255,255,255,0.15)"}} />
              {(opp.form||FORMS[0]).s.map((pos,i)=>{const pid=opp.xi[i];const p=pid&&opp.sq.find(x=>x.id===pid);const[x,y]=(opp.form||FORMS[0]).xy[i];
                return <div key={i} style={{position:"absolute",left:`${x}%`,top:`${y}%`,transform:"translate(-50%,-50%)",textAlign:"center",zIndex:2}}>
                  <div style={{width:18,height:18,borderRadius:99,background:p?(opp.c||["#fff","#fff"])[0]:"rgba(255,255,255,0.2)",border:p?`2px solid ${(opp.c||["#fff","#fff"])[1]}`:"1px dashed rgba(255,255,255,0.4)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:7,fontWeight:900,color:p?(opp.c||["#000","#fff"])[1]:"rgba(255,255,255,0.5)",margin:"0 auto"}}>{p?p.ovr:pos}</div>
                  <div style={{fontSize:6,color:"#ffd700",marginTop:1,whiteSpace:"nowrap",textShadow:"0 1px 3px #000"}}>{p?<>{p.nm.split(" ").pop()}{p.youth?<span style={{color:"#d0a030",fontWeight:"bold",marginLeft:1,fontSize:5}}>U21</span>:""}</>:pos}</div>
                </div>;})}
            </div>
          </div>
          {/* Squad list */}
          <div style={{padding:"6px 8px"}}>
            <div style={{fontSize:10,color:"#6090e0",fontWeight:"bold",marginBottom:3}}>Key Players</div>
            <table className="cm-table"><thead><tr><th style={{textAlign:"left"}}>Name</th><th>Pos</th><th>OVR</th><th>Fit</th></tr></thead>
            <tbody>{(()=>{
              const oppXI=opp.xi.map(id=>opp.sq.find(p=>p.id===id)).filter(Boolean).sort((a,b)=>b.ovr-a.ovr);
              return oppXI.map(p=><tr key={p.id}>
                <td style={{textAlign:"left",fontWeight:p.ovr>=Math.max(...oppXI.map(x=>x.ovr))-5?"bold":"normal",color:p.ovr>=Math.max(...oppXI.map(x=>x.ovr))-5?"#ffd700":"#c0c8e0"}}>{p.nm}{p.inj>0?" 🏥":""}</td>
                <td>{p.pos}</td>
                <td style={{fontWeight:"bold",color:p.ovr>=75?"#40ff40":p.ovr>=55?"#ffd700":"#ff6060"}}>{p.ovr}</td>
                <td style={{color:p.fit<60?"#ff4040":"#c0c8e0"}}>{p.fit}</td>
              </tr>);
            })()}</tbody></table>
          </div>
        </div>
      </div>:<>
      {/* Assistant advice */}
      <div style={{background:"#141830",borderBottom:"1px solid #2a3050",padding:"8px 10px"}}>
        <div style={{fontSize:10,color:"#6090e0",fontWeight:"bold",marginBottom:4}}>Asst. Manager:</div>
        <div style={{fontSize:10,color:"#8090b0",lineHeight:1.5}}>{asstAdvice}</div>
        <div style={{fontSize:10,color:"#8090b0",marginTop:4,fontStyle:"italic"}}>{asstSuggestion}</div>
      </div>
      {/* Team talk options */}
      <div className="cm-panel" style={{margin:2,flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        <div style={{padding:"6px 8px",fontWeight:"bold",color:"#6090e0",fontSize:11}}>Address the squad:</div>
        <div className="cm-sunken" style={{margin:"0 4px",flex:1,overflowY:"auto"}}>
          {TALKS.map(t=> <div key={t.id} onClick={()=>setTeamTalk(t.id)} style={{padding:"8px 10px",cursor:"pointer",borderBottom:"1px solid #1e2540",
            background:teamTalk===t.id?"#2040b0":"",border:teamTalk===t.id?"1px solid #4060c0":"1px solid transparent"}}
            onMouseEnter={e=>{if(teamTalk!==t.id)e.currentTarget.style.background="#1a2540";}}
            onMouseLeave={e=>{if(teamTalk!==t.id)e.currentTarget.style.background="";}}>
            <div style={{fontWeight:"bold",color:teamTalk===t.id?"#ffd700":"#c0c8e0",fontSize:12}}>"{t.label}"</div>
            <div style={{fontSize:9,color:teamTalk===t.id?"#8090c0":"#506080",marginTop:2}}>{t.desc}</div>
          </div>)}
        </div>
      </div></>}
    </div>
    );
  }

  // ── MAIN GAME ───────────────────────────────────────────
  const gamesLeft=38-wk;
  const TABS=[["squad","Squad"],["training","Training"],["tactics","Tactics"]];
  if(windowOpen)TABS.push(["transfer",24-wk<=2?`Window! ${24-wk}wk`:"Jan Window"]);
  TABS.push(["fix","Games"],["table","Table"],["news","News"]);

  return (
    <div style={{background:"#0e1220",minHeight:"100vh",fontFamily:"'Tahoma',sans-serif",fontSize:11,display:"flex",flexDirection:"column"}}>
      <style>{css}</style>
      {/* Team colour title bar */}
      <div style={{background:teamGrad(pt.c||["#cc1020","#ffd700"]),padding:"5px 10px",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:`1px solid ${(pt.c||["","#ffd700"])[1]}`}}>
        <span style={{fontFamily:"'Georgia','Times New Roman',serif",fontSize:14,fontWeight:900,color:"#fff",textShadow:"1px 1px 2px rgba(0,0,0,0.5)"}}>{pt.nm}</span>
        <span style={{fontSize:11,color:(pt.c||["","#ffd700"])[1],fontWeight:"bold"}}>{gamesLeft} games left</span>
      </div>
      {/* Status bar */}
      <div style={{background:"#141830",borderBottom:"1px solid #2a3050",padding:"5px 10px",display:"flex",gap:10,alignItems:"center",flexWrap:"wrap",justifyContent:"space-between"}}>
        <div style={{display:"flex",gap:10,alignItems:"center",flexWrap:"wrap",fontSize:12}}>
          <span style={{fontWeight:"bold",color:pPos>=18?"#ff4040":"#ffd700",fontSize:13}}>{pPos}{pPos===1?"st":pPos===2?"nd":pPos===3?"rd":"th"}</span>
          <span style={{color:"#8090b0"}}>P{pt.w+pt.d+pt.l} W{pt.w} D{pt.d} L{pt.l}</span>
          <span style={{fontWeight:"bold",color:pPos>=18?"#ff4040":"#40c040",fontSize:13}}>{pt.pts} pts</span>
          {windowOpen&&<><span style={{color:"#d0a030"}}>£{(pt.bud/1e6).toFixed(1)}M</span><span style={{color:24-wk<=2?"#ff4040":"#d0a030",fontSize:10}}>Window: {24-wk}wk</span></>}
        </div>
        <button className="cm-btn green" onClick={()=>{setTeamTalk(null);setTalkScreen(true);}} style={{fontWeight:"bold"}}>▶ Continue</button>
      </div>
      <div style={{display:"flex",gap:1,margin:"2px 2px 0",flexWrap:"wrap"}}>{TABS.map(([k,l])=> <button key={k} className={`cm-btn${tab===k?" act":""}`} onClick={()=>{setTab(k);setSel(null);setSelT(null);setSlotSel(null);}} style={{flex:"1 1 auto"}}>{l}</button>)}</div>

      <div className="cm-panel" style={{flex:1,margin:2,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        {sel&&<div style={{padding:6}}>
          <div className="cm-title" style={{marginBottom:2}}><span>{sel.nm}{sel.youth?<span style={{fontSize:10,color:"#d0a030",fontWeight:"bold",marginLeft:6}}>U21</span>:""} — {POS_L[sel.pos]} — Age {sel.age}</span><div style={{marginLeft:"auto",display:"flex",gap:2}}>{canSell?<button className="cm-btn" onClick={()=>sell(sel)} style={{fontSize:10,color:"#ff4040"}}>Sell £{((sel.val||0)/1e6).toFixed(1)}M</button>:<button className="cm-btn" style={{fontSize:10,opacity:0.3,cursor:"default"}}>Min squad</button>}<button className="cm-btn" onClick={()=>setSel(null)} style={{fontSize:10}}>✕</button></div></div>
          <div className="cm-sunken" style={{padding:6}}>
            <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:6,fontSize:10}}>
              <span>OVR: <b>{sel.ovr}</b></span><span>Fit: <b style={{color:sel.fit<60?"#c00":"#000"}}>{sel.fit}%</b></span>
              <span>Form: <b>{sel.frm}</b></span><span>Morale: <b>{sel.mor}</b></span>
              <span>Value: <b style={{color:"#ffd700"}}>£{((sel.val||0)/1e6).toFixed(1)}M</b></span>
              {sel.inj>0&&<span style={{color:"#ff4040",fontWeight:"bold"}}>INJURED {sel.inj}w</span>}
            </div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:3}}>
              {Object.entries(sel.at).map(([k,v])=> <div key={k} style={{textAlign:"center",background:v>=75?"#1a3a1a":v>=55?"#2a2a10":"#3a1a1a",padding:"3px 2px",border:"1px solid #2a3050"}}><div style={{fontSize:8,textTransform:"uppercase",color:"#6070a0"}}>{k.slice(0,3)}</div><div style={{fontSize:14,fontWeight:900,color:v>=75?"#40ff40":v>=55?"#ffd700":"#ff4040"}}>{v}</div></div>)}
            </div>
            <div style={{marginTop:6,fontSize:10,color:"#6070a0"}}>Apps:{sel.ap} Gls:{sel.g} Ast:{sel.a} YC:{sel.yc} RC:{sel.rc}</div>
          </div>
        </div>}

        {!sel&&<>
          {tab==="squad"&&<div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
            {/* Formation pitch */}
            <div style={{background:"repeating-linear-gradient(90deg, #1a5c2e 0px, #1a5c2e 20px, #1d6432 20px, #1d6432 40px)",position:"relative",height:280,margin:4,borderRadius:4,border:"2px solid #0e4020",flexShrink:0}}>
              <div style={{position:"absolute",inset:8,border:"1px solid rgba(255,255,255,0.25)"}} />
              <div style={{position:"absolute",left:8,right:8,top:"50%",height:1,background:"rgba(255,255,255,0.15)"}} />
              <div style={{position:"absolute",left:"50%",top:"50%",transform:"translate(-50%,-50%)",width:40,height:40,border:"1px solid rgba(255,255,255,0.15)",borderRadius:99}} />
              {/* Pitch markings - penalty areas */}
              <div style={{position:"absolute",left:"20%",right:"20%",bottom:8,height:"16%",border:"1px solid rgba(255,255,255,0.2)",borderBottom:"none"}} />
              <div style={{position:"absolute",left:"35%",right:"35%",bottom:8,height:"7%",border:"1px solid rgba(255,255,255,0.2)",borderBottom:"none"}} />
              <div style={{position:"absolute",left:"50%",bottom:"19%",transform:"translateX(-50%)",width:28,height:10,borderTopLeftRadius:28,borderTopRightRadius:28,borderTop:"1px solid rgba(255,255,255,0.15)",borderLeft:"1px solid rgba(255,255,255,0.15)",borderRight:"1px solid rgba(255,255,255,0.15)"}} />
              <div style={{position:"absolute",left:"20%",right:"20%",top:8,height:"16%",border:"1px solid rgba(255,255,255,0.2)",borderTop:"none"}} />
              <div style={{position:"absolute",left:"35%",right:"35%",top:8,height:"7%",border:"1px solid rgba(255,255,255,0.2)",borderTop:"none"}} />
              <div style={{position:"absolute",left:"50%",top:"19%",transform:"translateX(-50%)",width:28,height:10,borderBottomLeftRadius:28,borderBottomRightRadius:28,borderBottom:"1px solid rgba(255,255,255,0.15)",borderLeft:"1px solid rgba(255,255,255,0.15)",borderRight:"1px solid rgba(255,255,255,0.15)"}} />
              {pt.form.s.map((pos,i)=>{
                const pid=pt.xi[i];const p=pid&&pt.sq.find(x=>x.id===pid);
                const [x,y]=pt.form.xy[i];
                const isSel=slotSel&&slotSel.type==="xi"&&slotSel.idx===i;
                const arrow=tacArrow(pt.tac,pos);
                return <div key={i} onClick={()=>setSlotSel(isSel?null:{type:"xi",idx:i})} style={{position:"absolute",left:`${x}%`,top:`${y}%`,transform:"translate(-50%,-50%)",textAlign:"center",zIndex:2,cursor:"pointer",width:48}}>
                  {arrow==="↑"&&<div style={{fontSize:10,color:"rgba(255,255,255,0.5)",lineHeight:1,marginBottom:-2}}>↑</div>}
                  <div style={{width:26,height:26,borderRadius:99,margin:"0 auto",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:900,
                    background:isSel?"#ffd700":p?(pt.c||["#fff","#fff"])[0]:"rgba(255,255,255,0.15)",
                    color:isSel?"#000":p?(pt.c||["#000","#fff"])[1]:"rgba(255,255,255,0.4)",
                    border:isSel?"2px solid #fff":p?`2px solid ${(pt.c||["#fff","#fff"])[1]}`:"1px dashed rgba(255,255,255,0.3)",
                    boxShadow:isSel?"0 0 10px rgba(255,215,0,0.5)":"none"}}>{p?p.ovr:pos}</div>
                  <div style={{fontSize:7,color:isSel?"#fff":"#ffd700",marginTop:1,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",textShadow:"0 1px 3px #000"}}>{p?<>{p.nm.split(" ").pop()}{p.youth?<span style={{color:"#d0a030",fontWeight:"bold",marginLeft:1,fontSize:6}}>U21</span>:""}</>:pos}{isSel?" ✎":""}</div>
                  {arrow==="↓"&&<div style={{fontSize:10,color:"rgba(255,255,255,0.5)",lineHeight:1,marginTop:-1}}>↓</div>}
                </div>;
              })}
            </div>
            {/* Subs row */}
            <div style={{background:"#141830",border:"1px solid #2a3050",margin:"0 4px",padding:"4px 6px",display:"flex",gap:3,alignItems:"center",flexShrink:0}}>
              <span style={{fontSize:9,color:"#506080",marginRight:2}}>SUBS:</span>
              {[0,1,2,3,4].map(i=>{
                const pid=pt.sub[i];const p=pid&&pt.sq.find(x=>x.id===pid);
                const isSel=slotSel&&slotSel.type==="sub"&&slotSel.idx===i;
                return <div key={i} onClick={()=>setSlotSel(isSel?null:{type:"sub",idx:i})} style={{flex:1,background:isSel?"#2a3520":p?"#1a2040":"#0e1220",border:isSel?"1px solid #ffd700":p?"1px solid #2a3060":"1px dashed #252a3a",padding:"3px 2px",textAlign:"center",cursor:"pointer",fontSize:9,color:isSel?"#ffd700":p?"#c0c8e0":"#303848",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>
                  {p?<>{p.nm.split(" ").pop()}{p.youth?<span style={{color:"#d0a030",fontWeight:"bold",marginLeft:1,fontSize:7}}>U21</span>:""}</>:"—"}{isSel?" ✎":""}
                </div>;
              })}
            </div>
            {/* Prompt or legend */}
            {slotSel?<div style={{background:"#1a2040",border:"1px solid #2a3050",margin:"2px 4px",padding:"5px 8px",textAlign:"center",fontSize:11,color:"#ffd700",fontWeight:"bold",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span>Select player for {slotSel.type==="xi"?pt.form.s[slotSel.idx]:`Sub ${slotSel.idx+1}`}{(()=>{const pid=slotSel.type==="xi"?pt.xi[slotSel.idx]:pt.sub[slotSel.idx];const p=pid&&pt.sq.find(x=>x.id===pid);return p?` — replacing ${p.nm.split(" ").pop()} (${p.ovr})`:""})()}</span>
              <button className="cm-btn" onClick={()=>setSlotSel(null)} style={{fontSize:9,padding:"1px 6px"}}>Cancel</button>
            </div>
            :<div style={{margin:"2px 4px",padding:"4px",textAlign:"center",fontSize:9,color:"#506080"}}>Tap a position to change it. Tap ⓘ for player details.</div>}
            {/* Player list */}
            <div className="cm-sunken" style={{flex:1,overflowY:"auto",margin:"0 4px 4px"}}>
              <table className="cm-table">
                <thead><tr>
                  <th style={{width:24}}>#</th>
                  <th style={{textAlign:"left"}}>Name</th>
                  <th>Pos</th>
                  <th>OVR</th>
                  <th>Fit</th>
                  <th>Avg</th>
                  <th>Apps</th>
                  <th>G</th>
                  <th>A</th>
                  <th>Y/R</th>
                  <th>Mor</th>
                  <th style={{width:24}}></th>
                </tr></thead>
                <tbody>{(()=>{
                  const assigned=new Set([...pt.xi,...pt.sub]);
                  const sq=[...pt.sq];
                  const slotPos=slotSel&&slotSel.type==="xi"?pt.form.s[slotSel.idx]:null;
                  const posOrd={GK:0,DL:1,DC:2,DR:3,DM:4,ML:5,MC:6,MR:7,AM:8,ST:9};
                  sq.sort((a,b)=>{
                    if(slotPos){const am=a.pos===slotPos?0:1;const bm=b.pos===slotPos?0:1;if(am!==bm)return am-bm;}
                    const pa=posOrd[a.pos]??5,pb=posOrd[b.pos]??5;
                    if(pa!==pb)return pa-pb;
                    return b.ovr-a.ovr;
                  });
                  return sq.map(p=>{
                    const isAssigned=assigned.has(p.id);
                    const isMatch=slotPos&&p.pos===slotPos;
                    const xiIdx=pt.xi.indexOf(p.id);
                    const subIdx=pt.sub.indexOf(p.id);
                    const sqNum=xiIdx>=0?(xiIdx+1):subIdx>=0?`S${subIdx+1}`:"";
                    const avg=(p.frm/99*6+4).toFixed(1);
                    const avgCol=avg>=7.5?"#40ff40":avg>=6.5?"#ffd700":avg>=5.5?"#c0c8e0":"#ff6060";
                    const mor=moraleWord(p.mor||50);
                    const injDim=p.inj>0;
                    const slotDim=isAssigned&&slotSel&&p.inj===0;
                    return <tr key={p.id} className={isMatch&&!isAssigned&&p.inj===0?"xi":""} style={{opacity:slotDim?0.35:1,cursor:slotSel&&!isAssigned&&p.inj===0?"pointer":"default"}}
                      onClick={()=>{if(slotSel&&!isAssigned&&p.inj===0)assignToSlot(p.id);}}>
                      <td style={{color:xiIdx>=0?"#40c040":subIdx>=0?"#4080e0":"#303848",fontWeight:"bold",fontSize:9,opacity:injDim?0.35:1}}>{sqNum}</td>
                      <td style={{textAlign:"left",fontWeight:isMatch?"bold":"normal",opacity:injDim?0.35:1}}>{p.nm}{p.inj>0?" 🏥":""}{p.youth?<span style={{fontSize:8,color:"#d0a030",fontWeight:"bold",marginLeft:4}}>U21</span>:""}{p.signedWk!=null&&wk-p.signedWk<4?<span style={{fontSize:8,color:"#40c040",fontWeight:"bold",marginLeft:4}}>NEW</span>:""}</td>
                      <td style={{opacity:injDim?0.35:1}}>{p.pos}</td>
                      <td style={{fontWeight:"bold",color:p.ovr>=75?"#40ff40":p.ovr>=55?"#ffd700":"#ff6060",opacity:injDim?0.35:1}}>{p.ovr}</td>
                      <td style={{color:p.fit<60?"#ff4040":"#c0c8e0",opacity:injDim?0.35:1}}>{p.fit}</td>
                      <td style={{color:avgCol,fontWeight:"bold",opacity:injDim?0.35:1}}>{avg}</td>
                      <td style={{opacity:injDim?0.35:1}}>{p.ap||0}</td>
                      <td style={{opacity:injDim?0.35:1}}>{p.g||0}</td>
                      <td style={{opacity:injDim?0.35:1}}>{p.a||0}</td>
                      <td style={{fontSize:9,opacity:injDim?0.35:1}}>{(p.yc||0)}/{(p.rc||0)}</td>
                      <td style={{color:mor.col,fontSize:9,opacity:injDim?0.35:1}}>{mor.txt}</td>
                      <td><button type="button" className="cm-btn" onClick={e=>{e.stopPropagation();setSel(p);}} style={{fontSize:8,padding:"1px 4px",minHeight:18,background:"#2040b0",color:"#fff",borderRadius:99,width:20,height:20,display:"flex",alignItems:"center",justifyContent:"center"}}>i</button></td>
                    </tr>;
                  });
                })()}</tbody>
              </table>
            </div>
          </div>}

          {tab==="training"&&<div style={{flex:1,overflowY:"auto",padding:8}}>
            <div style={{fontWeight:"bold",color:"#6090e0",marginBottom:6}}>Training Focus This Week</div>
            <div style={{fontSize:10,color:"#8090b0",marginBottom:8}}>Choose what to focus on in training before the next match. Effects build up over time.</div>
            <div style={{display:"flex",flexDirection:"column",gap:4}}>
              {TRAIN_OPTS.map(t=> <div key={t} onClick={()=>setTraining(t)} style={{padding:"8px 10px",background:training===t?"#2040b0":"#0e1220",color:training===t?"#ffd700":"#c0c8e0",cursor:"pointer",border:"1px solid #2a3050",display:"flex",justifyContent:"space-between",alignItems:"center"}}
                onMouseEnter={e=>{if(training!==t){e.currentTarget.style.background="#1a2540";}}}
                onMouseLeave={e=>{if(training!==t){e.currentTarget.style.background="#0e1220";}}}>
                <div><div style={{fontWeight:"bold"}}>{t}</div><div style={{fontSize:9,color:training===t?"#8090c0":"#506080",marginTop:2}}>
                  {t==="Fitness"?"Improves stamina and fitness across the squad. Recommended early on.":
                   t==="Defending"?"Works on tackling and positioning. Helps keep clean sheets.":
                   t==="Attacking"?"Focuses on shooting and creativity. Helps score more goals.":
                   "Practises set pieces. Goals from corners and free kicks."}
                </div></div>
                {training===t&&<span style={{fontSize:14}}>{"✓"}</span>}
              </div>)}
            </div>
            {trainHist.length>0&&<div style={{marginTop:12}}>
              <div style={{fontWeight:"bold",color:"#6090e0",marginBottom:4,fontSize:10}}>Training History</div>
              <div style={{fontSize:10,color:"#6070a0"}}>{trainHist.map((t,i)=> <span key={i} style={{marginRight:6}}>Wk{19+i+1}: {t}</span>)}</div>
            </div>}
          </div>}

          {tab==="tactics"&&<div style={{flex:1,overflowY:"auto",padding:6}}>
            <div style={{fontWeight:"bold",color:"#6090e0",marginBottom:4}}>Formation</div>
            <div style={{display:"flex",gap:2,flexWrap:"wrap",marginBottom:8}}>{FORMS.map(f=> <button key={f.n} className={`cm-btn${pt.form.n===f.n?" act":""}`} onClick={()=>setForm(f)}>{f.n}</button>)}</div>
            <div style={{fontWeight:"bold",color:"#6090e0",marginBottom:4}}>Tactic</div>
            <div style={{display:"flex",gap:2,flexWrap:"wrap",marginBottom:8}}>{TACS.map(t=> <button key={t} className={`cm-btn${pt.tac===t?" act":""}`} onClick={()=>setTac(t)}>{t}</button>)}</div>
            <div style={{fontWeight:"bold",color:"#6090e0",marginBottom:4}}>Playing Style</div>
            <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:8,fontSize:10}}>
              <div>
                <div style={{color:"#506080",marginBottom:2}}>Passing:</div>
                <div style={{display:"flex",gap:2}}>{["Short","Mixed","Direct"].map(v=><button key={v} className={`cm-btn${pt.pass===v?" act":""}`} onClick={()=>{const nt=[...teams];nt[pIdx]={...nt[pIdx],pass:v};setTeams(nt);}} style={{fontSize:9,padding:"2px 6px"}}>{v}</button>)}</div>
              </div>
              <div>
                <div style={{color:"#506080",marginBottom:2}}>Tackling:</div>
                <div style={{display:"flex",gap:2}}>{["Easy","Normal","Hard"].map(v=><button key={v} className={`cm-btn${pt.tackle===v?" act":""}`} onClick={()=>{const nt=[...teams];nt[pIdx]={...nt[pIdx],tackle:v};setTeams(nt);}} style={{fontSize:9,padding:"2px 6px"}}>{v}</button>)}</div>
              </div>
            </div>
            <div style={{display:"flex",gap:8,marginBottom:8}}>
              <button className={`cm-btn${pt.press?" act":""}`} onClick={()=>{const nt=[...teams];nt[pIdx]={...nt[pIdx],press:!nt[pIdx].press};setTeams(nt);}} style={{fontSize:10}}>Pressing: {pt.press?"ON":"OFF"}</button>
              <button className={`cm-btn${pt.offside?" act":""}`} onClick={()=>{const nt=[...teams];nt[pIdx]={...nt[pIdx],offside:!nt[pIdx].offside};setTeams(nt);}} style={{fontSize:10}}>Offside Trap: {pt.offside?"ON":"OFF"}</button>
            </div>
            <div style={{background:"repeating-linear-gradient(90deg, #1a5c2e 0px, #1a5c2e 20px, #1d6432 20px, #1d6432 40px)",borderRadius:4,padding:12,position:"relative",height:280,border:"2px solid #0e4020"}}>
              <div style={{position:"absolute",inset:12,border:"1px solid rgba(255,255,255,0.3)"}} />
              <div style={{position:"absolute",left:12,right:12,top:"50%",height:1,background:"rgba(255,255,255,0.2)"}} />
              <div style={{position:"absolute",left:"50%",top:"50%",transform:"translate(-50%,-50%)",width:40,height:40,border:"1px solid rgba(255,255,255,0.2)",borderRadius:99}} />
              {/* Pitch markings - penalty areas */}
              <div style={{position:"absolute",left:"20%",right:"20%",bottom:12,height:"16%",border:"1px solid rgba(255,255,255,0.2)",borderBottom:"none"}} />
              <div style={{position:"absolute",left:"35%",right:"35%",bottom:12,height:"7%",border:"1px solid rgba(255,255,255,0.2)",borderBottom:"none"}} />
              <div style={{position:"absolute",left:"50%",bottom:"20%",transform:"translateX(-50%)",width:28,height:10,borderTopLeftRadius:28,borderTopRightRadius:28,borderTop:"1px solid rgba(255,255,255,0.15)",borderLeft:"1px solid rgba(255,255,255,0.15)",borderRight:"1px solid rgba(255,255,255,0.15)"}} />
              <div style={{position:"absolute",left:"20%",right:"20%",top:12,height:"16%",border:"1px solid rgba(255,255,255,0.2)",borderTop:"none"}} />
              <div style={{position:"absolute",left:"35%",right:"35%",top:12,height:"7%",border:"1px solid rgba(255,255,255,0.2)",borderTop:"none"}} />
              <div style={{position:"absolute",left:"50%",top:"20%",transform:"translateX(-50%)",width:28,height:10,borderBottomLeftRadius:28,borderBottomRightRadius:28,borderBottom:"1px solid rgba(255,255,255,0.15)",borderLeft:"1px solid rgba(255,255,255,0.15)",borderRight:"1px solid rgba(255,255,255,0.15)"}} />
              {pt.form.s.map((pos,i)=>{const pid=pt.xi[i];const p=pid&&pt.sq.find(x=>x.id===pid);const[x,y]=pt.form.xy[i];
                const arrow=tacArrow(pt.tac,pos);
                return <div key={i} style={{position:"absolute",left:`${x}%`,top:`${y}%`,transform:"translate(-50%,-50%)",textAlign:"center",zIndex:2}}>
                  {arrow==="↑"&&<div style={{fontSize:11,color:"rgba(255,255,255,0.5)",lineHeight:1,marginBottom:-2}}>↑</div>}
                  <div style={{width:24,height:24,borderRadius:99,background:p?(pt.c||["#fff","#fff"])[0]:"rgba(255,255,255,0.2)",border:p?`2px solid ${(pt.c||["#fff","#fff"])[1]}`:"1px dashed rgba(255,255,255,0.4)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:900,color:p?(pt.c||["#000","#fff"])[1]:"rgba(255,255,255,0.5)",margin:"0 auto"}}>{p?p.ovr:pos}</div>
                  <div style={{fontSize:7,color:"#ffd700",marginTop:1,whiteSpace:"nowrap",textShadow:"0 1px 3px #000"}}>{p?<>{p.nm.split(" ").pop()}{p.youth?<span style={{color:"#d0a030",fontWeight:"bold",marginLeft:1,fontSize:6}}>U21</span>:""}</>:pos}</div>
                  {arrow==="↓"&&<div style={{fontSize:11,color:"rgba(255,255,255,0.5)",lineHeight:1,marginTop:-1}}>↓</div>}
                </div>;})}
            </div>
          </div>}

          {tab==="transfer"&&windowOpen&&<div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
            {selT?<div style={{padding:6}}>
              <div className="cm-title" style={{marginBottom:2}}><span>{selT.nm} — {POS_L[selT.pos]} — Age {selT.age}</span><div style={{marginLeft:"auto",display:"flex",gap:2}}>
                {canBuy&&pt.bud>=selT.ask?<button className="cm-btn green" onClick={()=>{buy(selT);setSelT(null);}} style={{fontSize:10}}>Sign £{(selT.ask/1e6).toFixed(1)}M</button>
                :<button className="cm-btn" style={{fontSize:10,opacity:0.4,cursor:"default"}}>{loanCount>=10?"Loan limit":"Can't afford"}</button>}
                <button className="cm-btn" onClick={()=>setSelT(null)} style={{fontSize:10}}>✕</button>
              </div></div>
              <div className="cm-sunken" style={{padding:6}}>
                <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:6,fontSize:10}}>
                  <span>OVR: <b>{selT.ovr}</b></span>
                  <span>Fit: <b style={{color:selT.fit<60?"#ff4040":"#c0c8e0"}}>{selT.fit}%</b></span>
                  <span>Avg: <b style={{color:(selT.frm/99*6+4)>=7.0?"#40ff40":(selT.frm/99*6+4)>=6.0?"#ffd700":"#ff6060"}}>{(selT.frm/99*6+4).toFixed(1)}</b></span>
                  <span>From: <b>{selT.club}</b></span>
                  <span>Price: <b style={{color:"#ffd700"}}>£{(selT.ask/1e6).toFixed(1)}M</b></span>
                  <span>Budget: <b style={{color:"#40c040"}}>£{(pt.bud/1e6).toFixed(1)}M</b></span>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:3}}>
                  {Object.entries(selT.at).map(([k,v])=> <div key={k} style={{textAlign:"center",background:v>=75?"#1a3a1a":v>=55?"#2a2a10":"#3a1a1a",padding:"3px 2px",border:"1px solid #2a3050"}}><div style={{fontSize:8,textTransform:"uppercase",color:"#6070a0"}}>{k.slice(0,3)}</div><div style={{fontSize:14,fontWeight:900,color:v>=75?"#40ff40":v>=55?"#ffd700":"#ff4040"}}>{v}</div></div>)}
                </div>
              </div>
            </div>
            :<>
              <div style={{padding:"3px 6px",fontWeight:"bold",color:"#6090e0",display:"flex",gap:8,flexWrap:"wrap",fontSize:10}}>
                <span>Budget: <span style={{color:"#ffd700"}}>£{(pt.bud/1e6).toFixed(1)}M</span></span>
                <span>Squad: <span style={{color:pt.sq.length>=30?"#ff4040":"#c0c8e0"}}>{pt.sq.filter(p=>!p.youth).length}</span></span>
                <span>Loans: <span style={{color:loanCount>=10?"#ff4040":"#c0c8e0"}}>{loanCount}/10</span></span>
              </div>
              <div className="cm-sunken" style={{flex:1,overflowY:"auto",overflowX:"auto"}}>
                <table className="cm-table"><thead><tr><th style={{textAlign:"left"}}>Name</th><th>Pos</th><th>OVR</th><th>Fit</th><th>Avg</th><th className="hide-mob">From</th><th>£M</th></tr></thead>
                  <tbody>{tList.map(p=>{const avg=(p.frm/99*6+4).toFixed(1);return <tr key={p.id} onClick={()=>setSelT(p)} style={{cursor:"pointer"}}><td style={{textAlign:"left"}}>{p.nm}</td><td>{p.pos}</td>
                    <td style={{fontWeight:"bold",color:p.ovr>=75?"#40ff40":p.ovr>=55?"#ffd700":"#ff6060"}}>{p.ovr}</td>
                    <td style={{color:p.fit<60?"#ff4040":"#c0c8e0"}}>{p.fit}</td>
                    <td style={{fontWeight:"bold",color:avg>=7.0?"#40ff40":avg>=6.0?"#ffd700":"#ff6060"}}>{avg}</td>
                    <td className="hide-mob" style={{fontSize:9}}>{p.club}</td><td>{(p.ask/1e6).toFixed(1)}</td>
                  </tr>;})}</tbody>
                </table>
              </div>
            </>}
          </div>}

          {tab==="fix"&&<div ref={gamesRef} style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
            {/* Form strip */}
            {(()=>{
              const myRes=fix.slice(19).map((round,ri)=>{const m=round.find(m=>m.h===pIdx||m.a===pIdx);if(!m||!m.done)return null;
                const isH=m.h===pIdx;const myG=isH?m.hg:m.ag;const thG=isH?m.ag:m.hg;
                return myG>thG?"W":myG<thG?"L":"D";}).filter(Boolean);
              const last6=myRes.slice(-6);
              return <div style={{margin:4,padding:"6px 8px",background:"#141830",border:"1px solid #2a3050",display:"flex",justifyContent:"space-between",alignItems:"center",flexShrink:0}}>
                <div style={{display:"flex",gap:3,alignItems:"center"}}>
                  <span style={{fontWeight:"bold",color:"#6090e0",fontSize:10,marginRight:4}}>Form:</span>
                  {last6.length===0?<span style={{color:"#506080",fontSize:10}}>—</span>:
                  last6.map((r,i)=><div key={i} style={{width:20,height:20,borderRadius:3,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:900,
                    background:r==="W"?"#2a6a2a":r==="L"?"#8a2020":"#5a5a20",
                    color:r==="W"?"#40ff40":r==="L"?"#ff6060":"#ffd700"}}>{r}</div>)}
                </div>
                <span style={{fontSize:10,color:"#8090b0"}}>{pt.pts} pts</span>
              </div>;
            })()}
            {/* Sub-tabs */}
            <div style={{display:"flex",gap:1,margin:"0 4px",flexShrink:0}}>
              <button className={`cm-btn${fixSub==="results"?" act":""}`} onClick={()=>setFixSub("results")} style={{flex:1}}>Results</button>
              <button className={`cm-btn${fixSub==="fixtures"?" act":""}`} onClick={()=>setFixSub("fixtures")} style={{flex:1}}>Fixtures</button>
            </div>
            <div style={{flex:1,overflowY:"auto",padding:"0 4px 4px"}}>
            {fixSub==="results"?<>{fix.slice(0,wk).map((round,ri)=>{
              const realWk=ri;
              const isPast=round[0]?.done;
              const isPreAppt=realWk<19;
              return <div key={ri}>
                <div style={{padding:"4px 6px",fontSize:10,fontWeight:"bold",
                  background:isPast?"#141830":"#0e1220",
                  color:isPreAppt?"#405060":isPast?"#6090e0":"#506080",
                  borderBottom:"1px solid #1e2540"}}>
                  Week {realWk+1}
                </div>
                {round.map((m,mi)=>{
                  if(!m.done)return null;
                  const ip=m.h===pIdx||m.a===pIdx;
                  const isH=m.h===pIdx;
                  let res="";if(ip){const myG=isH?m.hg:m.ag;const thG=isH?m.ag:m.hg;res=myG>thG?"W":myG<thG?"L":"D";}
                  const resCol=res==="W"?"#40c040":res==="L"?"#ff4040":res==="D"?"#ffd700":"";
                  return <div key={mi} style={{padding:"2px 10px",fontSize:10,display:"flex",justifyContent:"space-between",alignItems:"center",
                    color:ip?"#c0c8e0":isPreAppt?"#384060":"#506080",fontWeight:ip?"bold":"normal",
                    background:ip?"rgba(32,64,176,0.1)":"",
                    borderBottom:"1px solid #0e1220"}}>
                    <span style={{flex:1,textAlign:"right"}}>{teams[m.h]?.nm}</span>
                    <span style={{width:40,textAlign:"center",fontWeight:900,color:ip?"#ffd700":isPreAppt?"#384060":"#6070a0"}}>{m.hg} - {m.ag}</span>
                    <span style={{flex:1}}>{teams[m.a]?.nm}</span>
                    {res&&<span style={{width:20,textAlign:"center",fontWeight:900,fontSize:9,color:resCol}}>{res}</span>}
                  </div>;
                })}
                {realWk===19&&<div style={{padding:"6px 8px",fontSize:10,fontWeight:"bold",color:"#ffd700",background:"#2a1a10",borderTop:"1px solid #ffd700",borderBottom:"1px solid #ffd700",textAlign:"center"}}>— You took charge here —</div>}
              </div>;
            }).reverse()}</>
            :<>{fix.slice(wk).map((round,ri)=>{
              const realWk=wk+ri;
              const isNow=realWk===wk;
              return <div key={ri}>
                <div ref={isNow?nextGameRef:null} style={{padding:"4px 6px",fontSize:10,fontWeight:"bold",
                  background:isNow?"#2040b0":"#0e1220",
                  color:isNow?"#ffd700":"#506080",
                  borderBottom:"1px solid #1e2540"}}>
                  {isNow?"▶ ":""}Week {realWk+1}{isNow?" — NEXT":""}
                </div>
                {round.map((m,mi)=>{
                  const ip=m.h===pIdx||m.a===pIdx;
                  if(m.done){
                    const isH=m.h===pIdx;
                    let res="";if(ip){const myG=isH?m.hg:m.ag;const thG=isH?m.ag:m.hg;res=myG>thG?"W":myG<thG?"L":"D";}
                    const resCol=res==="W"?"#40c040":res==="L"?"#ff4040":res==="D"?"#ffd700":"";
                    return <div key={mi} style={{padding:"2px 10px",fontSize:10,display:"flex",justifyContent:"space-between",alignItems:"center",
                      color:ip?"#c0c8e0":"#506080",fontWeight:ip?"bold":"normal",
                      background:ip?"rgba(32,64,176,0.1)":"",
                      borderBottom:"1px solid #0e1220"}}>
                      <span style={{flex:1,textAlign:"right"}}>{teams[m.h]?.nm}</span>
                      <span style={{width:40,textAlign:"center",fontWeight:900,color:ip?"#ffd700":"#6070a0"}}>{m.hg} - {m.ag}</span>
                      <span style={{flex:1}}>{teams[m.a]?.nm}</span>
                      {res&&<span style={{width:20,textAlign:"center",fontWeight:900,fontSize:9,color:resCol}}>{res}</span>}
                    </div>;
                  }
                  return <div key={mi} style={{padding:"2px 10px",fontSize:10,display:"flex",justifyContent:"space-between",
                    color:ip?"#ffd700":"#405060",fontWeight:ip?"bold":"normal",
                    background:ip&&isNow?"rgba(32,64,176,0.15)":"",
                    borderBottom:"1px solid #0e1220"}}>
                    <span style={{flex:1,textAlign:"right"}}>{teams[m.h]?.nm}</span>
                    <span style={{width:40,textAlign:"center",color:"#506080"}}>v</span>
                    <span style={{flex:1}}>{teams[m.a]?.nm}</span>
                  </div>;
                })}
              </div>;
            })}</>}
            </div>
          </div>}

          {tab==="table"&&<div style={{flex:1,overflowY:"auto"}}><div className="cm-sunken" style={{margin:4}}>
            <table className="cm-table"><thead><tr><th>#</th><th style={{textAlign:"left"}}>Team</th><th>P</th><th>W</th><th>D</th><th>L</th><th className="hide-mob">GF</th><th className="hide-mob">GA</th><th>GD</th><th>Pts</th></tr></thead>
              <tbody>{sorted.map((t,i)=> <tr key={t.id} className={t.isP?"sel":i>=17?"rel":""}><td style={{fontWeight:"bold"}}>{i+1}</td><td style={{textAlign:"left",fontWeight:t.isP?"bold":"normal"}}>{t.nm}</td><td>{t.w+t.d+t.l}</td><td>{t.w}</td><td>{t.d}</td><td>{t.l}</td><td className="hide-mob">{t.gf}</td><td className="hide-mob">{t.ga}</td><td style={{color:t.gf-t.ga>0?"#40c040":t.gf-t.ga<0?"#ff4040":"#506080"}}>{t.gf-t.ga>0?"+":""}{t.gf-t.ga}</td><td style={{fontWeight:900,color:"#ffd700"}}>{t.pts}</td></tr>)}</tbody>
            </table>
          </div></div>}

          {tab==="news"&&<div style={{flex:1,overflowY:"auto"}}><div className="cm-sunken" style={{margin:4}}>
            {[...news].reverse().map((n,i)=> <div key={i} style={{padding:n.fr?"6px":"3px 6px",borderBottom:"1px solid #1e2540",fontSize:10,borderLeft:n.pc?"3px solid #ffd700":"none",paddingLeft:n.pc?7:undefined}}>
              <span style={{color:"#506080",marginRight:6}}>Wk{n.w}</span>
              {n.fr?<><span style={{color:"#6090e0",fontWeight:"bold"}}>{n.fr}: </span><span style={{color:"#ffd700"}}>{n.su}</span><div style={{color:"#8090b0",marginTop:2,paddingLeft:2,whiteSpace:"pre-wrap"}}>{n.bo}</div></>
              :<span>{n.tx}</span>}
            </div>)}
          </div></div>}
        </>}
      </div>

    </div>
  );
}
